INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-18', E'예루살렘의 함락 (에스겔 35장)', E'에스겔 35장', E'에돔은 이스라엘과 뿌리를 같이하는 형제의 나라였습니다. 야곱의 형 에서의 후손들이 세운 나라가 바로 에돔이었기 때문입니다. 그러나 이들은 역사 속에서 끊임없이 갈등하며 대립해왔습니다. 특히 B.C. 586년 바벨론이 예루살렘을 파괴할 때, 에돔은 형제의 고난을 기회로 삼아 칼을 들었습니다. 하나님께서는 에스겔을 통해 세일 산, 곧 에돔을 향한 심판의 메시지를 선포하십니다.\n\n에돔의 죄는 단순한 적대 행위를 넘어선 것이었습니다. 그들은 "옛날부터 한을 품고" 이스라엘의 환난을 자신들의 이익을 위한 기회로 삼았습니다. 형제가 어려움에 처했을 때 도움의 손길을 내밀기는커녕, 오히려 그들의 고통에 편승하여 약탈과 살육에 가담했던 것입니다. 더욱이 에돔은 "이 두 민족과 두 땅은 다 내 것이며 내 기업이 되리라"고 교만하게 선언했습니다. 이는 하나님의 백성과 그들의 기업을 탐낸 것일 뿐 아니라, 그 땅에 계신 하나님의 주권을 무시한 행위였습니다.\n\n하나님께서는 에돔의 이러한 행악에 대해 철저한 심판을 선포하십니다. 세일 산은 황무지가 되고, 그 성읍들은 영원히 폐허가 되어 다시는 거주하는 자가 없을 것입니다. 특히 주목할 점은 하나님께서 "네가 피를 미워하지 아니하였은즉 피가 너를 따르리라"고 말씀하신 부분입니다. 피를 흘리기를 즐겼던 에돔은 그들이 뿌린 대로 거두게 될 것입니다.\n\n이 심판의 말씀은 단지 에돔만을 위한 것이 아닙니다. 형제의 고난을 기뻐하고, 약자의 어려움을 기회로 삼으며, 하나님의 주권을 무시하는 모든 이들을 향한 경고입니다. 하나님께서는 당신의 백성을 괴롭히고 조롱하는 자들을 결코 그냥 두지 않으십니다. "내가 여호와인 줄을 너희가 알리라"는 선언은 역사의 주권자이신 하나님의 확고한 의지를 보여줍니다.', E'오늘의 핵심\n하나님께서는 형제의 고난을 기회로 삼아 악을 행한 에돔을 심판하시며, 역사의 주권자로서 당신의 백성을 지키시는 분임을 선포하십니다.\n\n묵상 질문\n1. 타인의 어려움을 나의 이익을 위한 기회로 삼은 적은 없나요?\n2. 형제를 향한 미움과 질투가 내 마음속에 자리 잡고 있지는 않나요?\n3. 하나님의 주권을 인정하며 이웃을 사랑하기 위해 오늘 무엇을 실천하겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-19', E'우주의 주권자 예수 그리스도 (골로새서 1장)', E'골로새서 1장', E'로마의 감옥에서 바울은 골로새 교회에 편지를 보내고 있습니다. 당시 골로새는 소아시아의 작은 도시였지만, 그리스 철학과 유대교의 율법주의, 동방의 신비종교가 뒤섞여 복음의 순수성을 위협하고 있었습니다. 바울은 에바브라를 통해 전해 들은 골로새 교회의 소식에 감사하면서도, 그들이 직면한 영적 위기를 간파하고 있었습니다.\n\n바울은 먼저 골로새 성도들의 믿음과 사랑, 그리고 소망을 들었다며 감사를 표합니다. 특별히 그들이 복음을 듣고 하나님의 은혜를 깨달은 날부터 열매를 맺으며 자라고 있다는 소식은 바울에게 큰 기쁨이었습니다. 하지만 바울의 관심은 단순한 안부에 그치지 않습니다. 그는 골로새 성도들이 "모든 신령한 지혜와 총명에 하나님의 뜻을 아는 것으로" 채워지기를 간절히 기도합니다.\n\n이어서 바울은 그리스도가 누구신지를 장엄하게 선포합니다. 그리스도는 보이지 않는 하나님의 형상이시며, 모든 피조물보다 먼저 나신 분이십니다. 만물이 그분으로 말미암아 창조되었고, 그분을 위하여 존재합니다. 바울이 이토록 그리스도의 위대함을 강조하는 것은 골로새의 거짓 교사들이 그리스도만으로는 부족하다고 가르쳤기 때문입니다. 그들은 특별한 지식이나 천사 숭배, 금욕적 수련이 추가로 필요하다고 주장했습니다.\n\n그러나 바울은 단호합니다. 그리스도 안에 모든 충만이 거하시며, 그분의 십자가 피로 만물이 하나님과 화목하게 되었습니다. 전에는 악한 행실로 하나님과 원수 되었던 우리가 이제는 그리스도의 죽음으로 화목하게 되어 거룩하고 흠 없는 자로 서게 되었습니다. 이것이 바로 "너희 안에 계신 그리스도시니 곧 영광의 소망"이라고 바울이 말하는 복음의 비밀입니다. 이 비밀은 만세와 만대로부터 감추어졌다가 이제 성도들에게 나타난 것으로, 그리스도께서 이방인들 안에도 내주하신다는 놀라운 진리를 담고 있습니다.\n\n바울은 이 복음을 전하기 위해 자신의 고난까지도 기뻐한다고 고백합니다. 그리스도의 남은 고난을 자신의 육체에 채우며 교회를 섬기는 것이 그의 소명이었습니다. 이처럼 그리스도의 충만함과 완전함을 아는 것은 단순한 지식이 아니라 삶의 변화와 헌신으로 이어지는 살아있는 진리입니다.', E'오늘의 핵심\n그리스도는 만물의 창조주이시며 교회의 머리이신 충만한 분으로, 그분 안에만 영광의 소망이 있으며 그분만으로 우리는 완전해질 수 있습니다.\n\n묵상 질문\n1. 내가 그리스도 외에 다른 것으로 영적 충만함을 찾고 있는 영역은 무엇인가요?\n2. "너희 안에 계신 그리스도"라는 말씀이 내 삶에서 어떤 의미로 다가오나요?\n3. 바울처럼 복음을 위한 수고와 헌신을 기쁨으로 여길 수 있는 믿음이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-20', E'우주의 주권자 예수 그리스도 (골로새서 2장)', E'골로새서 2장', E'골로새 교회는 당시 소아시아 지역에서 번성하던 다양한 철학과 종교 사상의 도전에 직면해 있었습니다. 영지주의자들은 그리스도만으로는 충분하지 않다고 주장하며, 특별한 지식과 신비적 체험을 추가로 요구했습니다. 이러한 상황에서 바울은 그리스도의 충만함과 완전성을 강력하게 선포합니다.\n\n바울은 먼저 자신이 골로새 교회를 위해 얼마나 힘쓰고 있는지를 밝히며, 그 목적이 성도들로 하여금 "하나님의 비밀인 그리스도"를 깨닫게 하려는 것임을 분명히 합니다. 그리스도 안에는 지혜와 지식의 모든 보화가 감추어져 있다는 선언은, 영지주의자들이 주장하는 특별한 지식이나 비밀 교훈이 따로 필요하지 않음을 보여줍니다. 진정한 지혜와 지식은 그리스도 안에 이미 완전하게 계시되어 있습니다.\n\n이어서 바울은 "그리스도 예수를 주로 받았으니 그 안에서 행하라"고 권면합니다. 이는 단순히 교리적 동의가 아니라 삶의 전 영역에서 그리스도의 주권을 인정하고 따르는 것을 의미합니다. 그리스도 안에 뿌리를 박고 세움을 받는다는 표현은 식물이 땅에 깊이 뿌리내려 양분을 공급받듯이, 우리의 신앙생활도 그리스도께 깊이 연결되어야 함을 가르쳐줍니다.\n\n바울은 특히 "철학과 헛된 속임수"를 경계하라고 강조합니다. 이는 하나님의 계시가 아닌 인간의 전통과 세상의 초등학문에 기초한 가르침들을 가리킵니다. 그리스도 안에는 신성의 모든 충만이 육체로 거하시기에, 우리는 그분 안에서 이미 충만하여졌습니다. 할례나 절기, 음식 규정 같은 외적 규례들은 그림자일 뿐이며, 실체는 그리스도이십니다.\n\n십자가에서 이루신 그리스도의 승리는 모든 통치자들과 권세들을 무력화시켰습니다. 우리를 정죄하던 법조문은 십자가에 못 박혔고, 이제 우리는 그리스도 안에서 참 자유를 누립니다. 따라서 누구도 인간이 만든 규례나 금욕주의적 관습으로 우리를 판단하거나 정죄할 수 없습니다. 이러한 것들은 겉으로는 경건해 보이지만 실제로는 육체를 따르는 것을 금하는 데 아무 유익이 없습니다.', E'오늘의 핵심\n그리스도 안에는 지혜와 지식의 모든 보화가 감추어져 있으며, 신성의 모든 충만이 육체로 거하시므로 우리는 그분 안에서 이미 완전함을 얻었습니다.\n\n묵상 질문\n1. 내 삶에서 그리스도 외에 다른 것들로 부족함을 채우려 했던 때는 언제였나요?\n2. 세상의 철학과 가르침이 아닌 그리스도 안에 뿌리를 내리기 위해 무엇을 해야 할까요?\n3. 종교적 규례나 외적 행위가 아닌 그리스도와의 관계로 충만한 삶을 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-21', E'우주의 주권자 예수 그리스도 (골로새서 3장)', E'골로새서 3장', E'바울은 골로새 교회 성도들에게 그리스도와 함께 다시 살리심을 받은 새로운 정체성을 상기시키며 이 편지의 실천적 교훈을 시작합니다. 골로새에 만연했던 영지주의와 금욕주의의 거짓된 가르침에 맞서, 바울은 참된 그리스도인의 삶이 무엇인지 구체적으로 제시하고 있습니다.\n\n"위의 것을 찾으라"는 권면은 단순히 현실을 도피하라는 의미가 아닙니다. 그리스도께서 하나님 우편에 앉아 계신 그 영광의 실재를 바라보며, 그분의 통치 원리에 따라 이 땅에서 살아가라는 말씀입니다. 우리의 생명이 그리스도와 함께 하나님 안에 감추어져 있다는 것은 우리의 존재 자체가 이미 새로운 차원으로 옮겨졌음을 의미합니다.\n\n바울은 벗어버려야 할 옛 성품들을 구체적으로 나열합니다. 음란, 부정, 탐심과 같은 육체적 죄들뿐 아니라 분함, 노여움, 비방과 같은 관계적 죄들도 포함됩니다. 이러한 것들은 단순한 도덕적 실패를 넘어 우상숭배의 본질을 드러내는 것들입니다. 반면 새 사람이 입어야 할 덕목들은 긍휼, 자비, 겸손, 온유, 오래 참음입니다. 이는 그리스도께서 우리에게 보여주신 성품들이며, 성령의 열매로 맺히는 것들입니다.\n\n특별히 바울은 사랑을 "온전하게 매는 띠"라고 표현합니다. 다른 모든 덕목들이 사랑 안에서 하나로 묶이고 완성된다는 뜻입니다. 그리스도의 평강이 마음을 다스리고, 그분의 말씀이 풍성히 거하며, 감사가 넘치는 공동체의 모습은 초대 교회가 추구했던 이상적인 모습입니다.\n\n바울은 이러한 원리들을 가정과 사회의 구체적인 관계들에 적용합니다. 부부 관계, 부모와 자녀 관계, 주인과 종의 관계에서도 그리스도의 주권이 인정되어야 합니다. "무슨 일을 하든지 마음을 다하여 주께 하듯" 하라는 권면은 일상의 모든 영역이 예배가 될 수 있음을 보여줍니다. 이것이 바로 그리스도의 완전함과 충만함 안에서 사는 삶의 모습입니다.', E'오늘의 핵심\n그리스도와 함께 다시 살리심을 받은 성도는 위의 것을 추구하며, 옛 사람을 벗고 새 사람을 입어 모든 관계와 일상에서 그리스도의 주권을 인정하는 삶을 살아야 합니다.\n\n묵상 질문\n1. 내가 추구하는 ''위의 것''은 무엇이며, 여전히 ''땅의 것''에 매여 있는 영역은 무엇인가요?\n2. 벗어버려야 할 옛 성품과 새롭게 입어야 할 덕목 중 가장 도전이 되는 것은 무엇인가요?\n3. 일상의 모든 일을 "주께 하듯" 한다면 내 삶은 어떻게 달라질까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-23', E'우주의 주권자 예수 그리스도 (골로새서 4장)', E'골로새서 4장', E'골로새서의 마지막 장에서 바울은 그리스도인의 일상적인 삶의 모습을 구체적으로 제시합니다. 먼저 주인과 종의 관계에서 정의와 공평을 강조하는데, 이는 단순한 사회적 윤리를 넘어 하늘에 계신 주인을 의식하는 신앙적 차원의 권면입니다. 당시 로마 사회에서 종은 주인의 소유물에 불과했지만, 바울은 복음 안에서 모든 사람이 하나님 앞에 평등함을 전제로 이러한 가르침을 주고 있습니다.\n\n바울은 기도의 삶에 대해서도 중요한 가르침을 줍니다. "기도를 계속하고 기도에 감사함으로 깨어 있으라"는 권면은 단순히 기도의 양을 늘리라는 것이 아니라, 감사하는 마음으로 하나님과의 지속적인 교제를 유지하라는 의미입니다. 특별히 바울은 자신을 위한 기도를 요청하면서 ''그리스도의 비밀''을 전할 수 있는 문이 열리기를 구합니다. 감옥에 갇혀 있으면서도 복음 전파에 대한 열정을 잃지 않는 모습을 통해 참된 사도의 마음을 보여줍니다.\n\n그리스도인의 지혜로운 처신에 대한 가르침도 주목할 만합니다. 믿지 않는 사람들에게 지혜롭게 행하며 기회를 선용하라는 권면과 함께, 언어생활에 있어서도 은혜롭고 소금으로 맛을 낸 것 같은 말을 하라고 가르칩니다. 이는 복음의 향기를 드러내는 삶의 구체적인 모습입니다.\n\n편지의 마지막 부분에서 바울은 여러 동역자들의 이름을 언급하며 안부를 전합니다. 두기고, 오네시모, 아리스다고, 마가, 예수 유스도, 에바브라, 누가, 데마 등 다양한 배경을 가진 사람들이 복음을 위해 함께 수고하는 모습을 보여줍니다. 특히 에바브라가 골로새 교인들을 위해 애써 기도하며 그들이 하나님의 뜻 가운데 완전하고 확신 있게 서기를 구한다는 내용은, 진정한 목회자의 마음이 무엇인지를 보여줍니다. 이처럼 초대교회는 서로를 위해 기도하고 격려하는 사랑의 공동체였음을 알 수 있습니다.', E'오늘의 핵심\n바울은 그리스도인의 일상적 삶 속에서 하늘의 주인을 의식하며 살아가야 함을 가르치고, 기도와 지혜로운 처신을 통해 복음의 향기를 드러내는 삶을 살도록 권면합니다.\n\n묵상 질문\n1. 내가 속한 공동체에서 정의와 공평을 실천하며 하나님을 의식하는 삶을 살고 있나요?\n2. 감사함으로 깨어 기도하는 삶을 통해 어떻게 복음 전파의 문이 열릴 수 있을까요?\n3. 믿지 않는 사람들에게 은혜롭고 지혜로운 말과 행동으로 그리스도의 향기를 나타내고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-24', E'기도로 여는 하늘문 (사무엘상 20장)', E'사무엘상 20장', E'사울의 살의가 걷잡을 수 없이 커지면서 다윗은 극도의 위기에 몰립니다. 라마 나욧에서 도망쳐 나온 다윗이 요나단을 찾아와 절박하게 묻습니다. "나와 죽음의 사이는 한 걸음뿐이니라"(삼상 20:3). 이 처절한 고백에는 억울함과 두려움이 가득합니다. 자신이 무엇을 잘못했기에 왕이 자신의 생명을 노리는지 알 수 없었던 다윗의 마음이 얼마나 답답했을까요.\n\n요나단은 친구의 생명을 지키기 위해 아버지의 마음을 살피기로 합니다. 초하루 왕의 식탁에서 다윗의 빈자리를 두고 사울의 반응을 확인하는 것이었습니다. 둘째 날 사울이 다윗의 부재를 묻자, 요나단은 다윗이 베들레헴의 가족 제사에 참석했다고 둘러댑니다. 그 순간 사울의 분노가 폭발합니다. 심지어 아들 요나단에게 단창을 던져 죽이려 할 정도였습니다.\n\n이 장면은 질투와 두려움이 한 사람을 얼마나 파괴적으로 만드는지 보여줍니다. 사울은 다윗이 자신의 왕위를 위협한다고 생각했습니다. 그러나 요나단의 반응은 달랐습니다. 그는 왕위 계승자임에도 불구하고 다윗이 하나님께 선택받은 사람임을 인정했습니다. "여호와께서 내 아버지와 함께 하신 것 같이 너와 함께 하시기를 원하노니"라는 요나단의 고백에는 하나님의 뜻에 순복하는 겸손한 믿음이 담겨 있습니다.\n\n에셀 바위에서의 마지막 만남은 두 친구의 우정이 얼마나 깊었는지를 보여줍니다. 화살을 신호로 삼아 위험을 알리는 요나단의 지혜로운 계획, 그리고 서로를 위해 눈물을 흘리며 작별하는 모습에서 우리는 진정한 우정의 아름다움을 봅니다. 요나단은 자신의 왕위 계승권보다 하나님의 뜻과 친구와의 언약을 더 소중히 여겼습니다. 이것이 바로 믿음의 사람이 보여주는 진정한 위대함입니다.', E'오늘의 핵심\n요나단은 왕위 계승권을 포기하면서까지 하나님의 뜻을 인정하고, 생명의 위협 속에서도 다윗과의 언약을 지켜 진정한 믿음의 우정을 보여줍니다.\n\n묵상 질문\n1. 나는 하나님의 뜻이 내 계획과 다를 때 요나단처럼 순복할 수 있을까요?\n2. 질투와 두려움이 내 마음을 지배하지 않도록 어떻게 경계하고 있나요?\n3. 하나님 앞에서 맺은 약속과 관계를 신실하게 지키고 있는지 돌아봅시다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-25', E'기도로 여는 하늘문 (사무엘상 21장)', E'사무엘상 21장', E'사울의 위협을 피해 도망친 다윗이 제사장들의 성읍 놉에 도착합니다. 떨리는 마음으로 다윗을 맞이한 아히멜렉 제사장은 왕의 사위이자 군대 장관인 다윗이 홀로 온 것을 의아해합니다. 다윗은 왕의 비밀 임무 수행 중이라고 둘러대며 먹을 것과 무기를 요청합니다. 긴박한 도피 상황에서 진실을 말할 수 없었던 다윗의 곤경이 드러나는 장면입니다.\n\n아히멜렉은 보통 떡은 없고 오직 거룩한 진설병만 있다고 답합니다. 율법에 따르면 진설병은 제사장만 먹을 수 있었지만, 아히멜렉은 생명의 위기에 처한 다윗에게 이를 내어줍니다. 또한 골리앗의 칼까지 건네주며 다윗을 돕습니다. 하나님의 기름부음 받은 자를 향한 제사장의 긍휼이 율법의 형식을 넘어섰습니다. 그러나 이 장면을 사울의 목자장 도엑이 지켜보고 있었다는 불길한 복선이 깔립니다.\n\n놉을 떠난 다윗은 더욱 절박한 선택을 합니다. 이스라엘의 원수 블레셋 땅으로 도망간 것입니다. 그러나 가드 왕 아기스의 신하들이 "사울이 죽인 자는 천천이요 다윗은 만만이로다"라는 노래를 언급하며 다윗의 정체를 알아봅니다. 궁지에 몰린 다윗은 미친 사람인 척하며 대문짝에 낙서하고 침을 흘립니다. 이스라엘의 영웅이 적국에서 광인 행세를 해야 했던 처절한 순간입니다.\n\n하나님의 약속을 받았지만 현실은 도피와 굴욕의 연속이었습니다. 그러나 다윗은 바로 이 시기에 시편 34편을 지어 "여호와를 찾는 자는 모든 좋은 것에 부족함이 없으리로다"라고 고백합니다. 가장 낮은 자리에서도 하나님을 신뢰하는 믿음, 이것이 다윗을 하나님의 마음에 합한 자로 만들어가는 과정이었습니다.', E'오늘의 핵심\n극한의 위기 속에서 거짓말과 미친 척하기까지 해야 했던 다윗의 모습을 통해, 하나님의 약속이 성취되기까지의 과정이 얼마나 험난한지를 보여줍니다. 그러나 다윗은 가장 비참한 순간에도 하나님을 찬양하는 믿음을 잃지 않았습니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 약속과 현실 사이의 간극으로 인해 좌절했던 때는 언제였나요?\n2. 생존을 위해 체면과 자존심을 내려놓아야 했던 다윗처럼, 나도 겸손히 낮아져야 할 영역이 있을까요?\n3. 가장 어려운 상황에서도 하나님을 찬양할 수 있는 믿음을 어떻게 키워갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-26', E'침략자 곡에 대한 심판과 멸망 (에스겔 38장)', E'에스겔 38장', E'에스겔 38장은 마곡 땅의 곡에 대한 심판 예언을 담고 있습니다. 바벨론 포로기의 어둠 속에서 하나님께서는 이스라엘의 대적들이 어떻게 심판받을 것인지를 미리 보여주심으로써 당신의 백성에게 소망을 주고 계십니다. 곡은 로스와 메섹과 두발의 왕으로, 북방에서 거대한 연합군을 이끌고 이스라엘을 침략하려는 자로 묘사됩니다. 그는 바사와 구스와 붓, 고멜과 도갈마 족속까지 규합하여 "구름 같이 땅을 덮으리라"(겔 38:9)고 표현될 만큼 압도적인 군세를 자랑합니다.\n\n그러나 하나님께서는 이 모든 계획을 이미 아시고 계셨습니다. 곡이 평안히 거주하는 이스라엘 백성을 노략하려는 악한 꾀를 품고 있음을 아시고, 오히려 그를 끌어내어 당신의 거룩하심을 나타내는 도구로 사용하시려는 것입니다. 하나님께서는 곡의 침략을 허락하시되, 그것이 바로 심판의 때가 될 것임을 선언하십니다. 큰 지진과 전염병, 폭우와 우박, 불과 유황으로 곡과 그의 모든 군대를 심판하실 것입니다. \n\n이 예언의 궁극적인 목적은 단순한 심판이 아닙니다. 하나님께서는 "내가 너로 말미암아 이방 사람의 눈 앞에서 내 거룩함을 나타내어 그들이 다 나를 알게 하려 함이라"고 말씀하십니다. 곡의 멸망을 통해 열방이 여호와 하나님을 알게 되리라는 것입니다. 포로 생활의 고통 속에서 신음하던 이스라엘 백성에게 이 예언은 하나님께서 여전히 역사의 주관자이시며, 당신의 백성을 잊지 않으셨다는 확신을 주었을 것입니다. 악이 승리하는 것처럼 보이는 순간에도 하나님의 주권적인 통치는 계속되고 있음을 보여줍니다.', E'오늘의 핵심\n하나님께서는 곡의 침략 계획을 미리 아시고 오히려 그것을 통해 당신의 거룩하심을 만방에 나타내시며, 포로 된 백성에게는 하나님이 여전히 역사의 주관자이심을 확신시켜 주십니다.\n\n묵상 질문\n1. 악이 득세하는 것 같은 현실 속에서도 하나님의 주권을 신뢰하고 있나요?\n2. 하나님께서 나의 어려움을 통해서도 당신의 영광을 나타내실 수 있음을 믿으시나요?\n3. 오늘 내가 평안히 거하는 것이 하나님의 보호하심 때문임을 감사하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-27', E'침략자 곡에 대한 심판과 멸망 (에스겔 39장)', E'에스겔 39장', E'에스겔 39장은 38장에서 시작된 곡에 대한 심판 예언이 절정에 이르는 장면을 보여줍니다. 하나님께서는 북방의 강대국 곡을 이끌어내어 이스라엘 산 위에서 완전히 멸망시키실 것을 선포하십니다. 곡의 군대가 얼마나 강력했는지는 그들의 무기를 7년 동안 땔감으로 사용할 정도라는 표현에서 잘 드러납니다. 그러나 하나님께서는 이 거대한 군대를 순식간에 무너뜨리시고, 그들의 시체가 이스라엘 땅에 가득할 것이라고 말씀하십니다.\n\n이 심판의 목적은 단순한 보복이 아니었습니다. "내가 여호와 곧 이스라엘의 거룩한 자인 줄을 민족들이 알리라"(겔 39:7)는 말씀처럼, 하나님께서는 당신의 거룩한 이름을 모든 민족 가운데 알리고자 하셨습니다. 곡의 멸망은 하나님의 주권과 능력을 온 세상에 증명하는 사건이 될 것입니다. \n\n특별히 주목할 것은 25절 이후에 나타나는 회복의 약속입니다. 하나님께서는 심판 이후에 "야곱의 사로잡힌 자를 돌아오게 하며 이스라엘 온 족속에게 사랑을 베풀지라"고 약속하십니다. 포로로 잡혀간 백성들은 이방 땅에서 하나님의 얼굴을 보지 못한다고 절망했을 것입니다. 그러나 하나님께서는 그들을 한 사람도 남김없이 고향으로 돌아오게 하시고, 더 나아가 성령을 부어주실 것을 약속하십니다.\n\n이 약속은 단순한 지리적 귀환을 넘어 영적인 회복을 의미합니다. 하나님께서 다시는 얼굴을 가리지 않으시고 성령을 부어주신다는 것은 하나님과 백성 사이의 관계가 완전히 회복될 것을 보여줍니다. 심판의 어두운 그림자 속에서도 하나님의 변함없는 사랑과 신실하심이 빛나고 있습니다.', E'오늘의 핵심\n하나님께서는 곡의 완전한 멸망을 통해 당신의 거룩함을 만방에 드러내시고, 동시에 이스라엘의 완전한 회복을 약속하심으로써 심판 너머에 있는 구원의 소망을 보여주십니다.\n\n묵상 질문\n1. 하나님의 심판이 궁극적으로 당신의 거룩함을 드러내기 위함임을 어떻게 이해하고 계신가요?\n2. 포로 생활의 절망 속에서도 하나님의 회복 약속을 붙잡는 믿음이 내게 있나요?\n3. 하나님께서 성령을 부어주신다는 약속이 오늘 나의 삶에 어떤 의미로 다가옵니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-28', E'임명권자 하나님 (사무엘상 23장)', E'사무엘상 23장', E'블레셋이 그일라를 침공했다는 소식이 다윗에게 전해집니다. 그일라는 유다 지파에게 분배된 성읍으로, 지금 막 추수한 곡식을 블레셋에게 약탈당하고 있었습니다. 사울에게 쫓기는 도망자 신세인 다윗에게는 이 일이 자신과 무관한 일일 수 있었습니다. 그러나 다윗은 여호와께 묻습니다. 하나님께서는 "가서 블레셋 사람들을 치고 그일라를 구원하라"(삼상 23:2)고 명하십니다. \n\n다윗의 부하들은 두려워합니다. 사울의 추격을 피해 숨어 지내는 것만도 벅찬데, 블레셋과 싸우는 것은 너무나 위험한 일이었기 때문입니다. 다윗은 다시 한 번 여호와께 묻고, 하나님의 확실한 응답을 받은 후에야 그일라로 향합니다. 이 과정은 다윗이 얼마나 철저하게 하나님의 뜻을 구하며 살았는지를 보여줍니다.\n\n그일라를 구원한 다윗이지만, 그곳 주민들은 사울이 군대를 이끌고 오자 다윗을 배신할 것이라는 하나님의 경고를 받습니다. 은혜를 원수로 갚는 인간의 연약함이 드러나는 순간입니다. 다윗은 실망하거나 원망하지 않고 조용히 그곳을 떠납니다. 이후 광야를 전전하며 사울의 추격을 피하던 다윗에게 요나단이 찾아옵니다. 요나단은 하나님의 약속을 상기시키며 다윗의 믿음을 굳게 세워줍니다. \n\n십 사람들까지 다윗의 행방을 밀고하는 상황에서, 다윗은 점점 더 궁지에 몰립니다. 마온 광야에서는 사울의 군대에 완전히 포위될 뻔했으나, 절체절명의 순간에 블레셋의 침공 소식이 전해져 사울이 철수합니다. 하나님께서는 다윗이 블레셋과 싸워 그일라를 구했던 그 블레셋을 통해 다윗을 구원하신 것입니다. 하나님의 섭리는 이처럼 신묘합니다.', E'오늘의 핵심\n도망자 신세임에도 하나님의 명령에 순종하여 그일라를 구원한 다윗은, 배신과 추격 속에서도 하나님의 특별한 보호하심을 경험합니다.\n\n묵상 질문\n1. 어려운 상황에서도 하나님의 뜻을 먼저 구하고 순종하는 삶을 살고 있나요?\n2. 선을 악으로 갚는 사람들을 만났을 때 어떻게 반응하시나요?\n3. 절망적인 순간에 하나님의 섭리를 경험한 적이 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-30', E'임명권자 하나님 (사무엘상 24장)', E'사무엘상 24장', E'엔게디 광야의 어느 굴에서 놀라운 일이 벌어집니다. 이스라엘 전체에서 선발된 삼천 명의 정예부대를 이끌고 다윗을 추격하던 사울이, 하필이면 다윗과 그의 사람들이 숨어있는 바로 그 굴로 들어온 것입니다. 운명의 장난처럼 보이는 이 순간, 다윗의 부하들은 흥분하여 속삭입니다. 하나님께서 원수를 다윗의 손에 넘기신다는 약속이 바로 지금 이루어지고 있다고 말입니다.\n\n그러나 다윗은 전혀 다른 선택을 합니다. 사울의 겉옷 자락만을 베어낸 후, 그마저도 마음에 찔림을 느낍니다. "내가 손을 들어 여호와의 기름 부음을 받은 내 주를 치는 것은 여호와께서 금하시는 것이니"(삼상 24:6)라는 그의 고백은, 자신의 안전보다 하나님의 주권을 더 중요하게 여기는 믿음의 결단을 보여줍니다. 왕위를 약속받았지만 그것을 자기 손으로 쟁취하지 않고 하나님의 때를 기다리는 다윗의 모습에서, 우리는 참된 믿음의 본질을 발견합니다.\n\n굴을 나와 사울을 부르는 다윗의 외침에는 억울함이 아닌 존경이 담겨 있습니다. 땅에 엎드려 절하며 "내 아버지여"라고 부르는 그의 모습은, 자신을 죽이려는 사울을 향한 깊은 연민과 사랑을 드러냅니다. 이 장면을 목격한 사울은 비로소 자신의 잘못을 깨닫고 눈물을 흘립니다. "너는 나보다 의롭도다"라는 사울의 고백은, 권력에 눈이 멀어 하나님의 뜻을 거스른 자신과 달리 끝까지 하나님의 방법을 선택한 다윗의 의로움을 인정하는 것이었습니다.\n\n다윗이 보여준 이러한 자비와 절제는 단순한 정치적 계산이나 도덕적 우월감에서 비롯된 것이 아닙니다. 그것은 하나님의 주권을 온전히 신뢰하는 믿음에서 나온 행동이었습니다. 복수할 수 있는 완벽한 기회를 포기하고 하나님께 심판을 맡기는 다윗의 모습은, 오늘 우리에게도 깊은 도전을 줍니다. 상처받고 억울한 상황에서도 하나님의 때와 방법을 기다릴 수 있는 믿음, 그것이 바로 다윗을 통해 하나님께서 우리에게 가르쳐 주시는 귀한 교훈입니다.', E'오늘의 핵심\n다윗은 사울을 죽일 수 있는 절호의 기회에도 불구하고 하나님의 기름 부음받은 자를 해치지 않음으로써, 하나님의 주권을 존중하고 그분의 때를 기다리는 참된 믿음의 본을 보여줍니다.\n\n묵상 질문\n1. 내 손에 복수할 기회가 주어질 때, 나는 하나님께 심판을 맡길 수 있을까요?\n2. 다윗처럼 원수를 "내 아버지"라고 부를 수 있는 사랑의 마음을 품고 있나요?\n3. 하나님의 약속을 기다리며 인내하는 것이 어려운 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-31', E'하나님의 테스트 (사무엘상 25장)', E'사무엘상 25장', E'시대의 거목이었던 사무엘이 하나님의 부르심을 받아 영원한 안식에 들어갑니다. 온 이스라엘이 모여 애도하는 가운데, 다윗은 홀로 바란 광야로 내려가야 했습니다. 영적 멘토의 부재는 다윗에게 큰 상실감을 안겨주었을 것입니다. 바로 이때 하나님께서는 뜻밖의 사건을 통해 다윗의 삶에 개입하십니다.\n\n갈멜의 부자 나발은 다윗과 그의 부하들이 목자들을 보호해준 은혜를 모욕으로 갚았습니다. 분노한 다윗이 칼을 차고 나발의 집을 치러 갈 때, 하나님께서는 총명한 여인 아비가일을 보내어 피의 보복을 막으십니다. 아비가일의 지혜로운 말은 다윗의 마음을 돌이켰습니다. "내 주의 손으로 피를 흘려 친히 보복하시는 일을 여호와께서 막으셨으니"(삼상 25:26)라는 그녀의 고백은 다윗으로 하여금 하나님의 섭리를 깨닫게 합니다.\n\n아비가일은 단순히 위기를 모면하려는 것이 아니었습니다. 그녀는 다윗이 장차 이스라엘의 지도자가 될 것을 내다보며, 무죄한 피를 흘리는 일이 훗날 그의 양심에 걸림돌이 되지 않기를 간구했습니다. 이는 다윗이 사울을 두 번이나 살려준 일과 같은 맥락에서, 하나님께서 복수를 친히 행하시도록 맡기는 믿음의 원칙을 다시 한번 확인시켜 줍니다.\n\n열흘 후 나발이 하나님의 치심으로 죽자, 다윗은 아비가일을 아내로 맞이합니다. 하나님께서는 사무엘이 떠난 빈자리를 지혜로운 동반자로 채워주신 것입니다. 이 사건은 우리에게 중요한 교훈을 줍니다. 감정적 대응이 아닌 하나님의 때와 방법을 기다리는 믿음, 그리고 위기의 순간에 하나님께서 예비하신 도움의 손길을 신뢰하는 것입니다.', E'오늘의 핵심\n하나님께서는 분노에 사로잡힌 다윗을 지혜로운 아비가일을 통해 막으시고, 복수를 친히 갚으시며 다윗에게 새로운 동반자를 허락하십니다.\n\n묵상 질문\n1. 분노와 복수심이 솟구칠 때, 나는 하나님의 음성에 귀를 기울이고 있나요?\n2. 내 삶에 아비가일처럼 지혜로운 조언을 해주는 사람이 있나요?\n3. 하나님께 복수를 맡기고 기다리는 믿음을 실천하고 계신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-01', E'하나님의 테스트 (사무엘상 26장)', E'사무엘상 26장', E'십 사람들이 다시 사울에게 다윗의 위치를 밀고합니다. 삼천 명의 정예군을 이끌고 하길라 산으로 출동한 사울은 진영 가운데 누워 잠들어 있었고, 다윗과 아비새가 그곳에 잠입했을 때 여호와께서 그들을 깊이 잠들게 하셨습니다. 아비새는 절호의 기회라며 사울을 단번에 죽이자고 제안하지만, 다윗은 단호히 거절합니다. "누구든지 손을 들어 여호와의 기름 부음 받은 자를 치면 죄가 없겠느냐"(삼상 26:9)는 다윗의 고백은 그가 여전히 하나님의 주권을 온전히 인정하고 있음을 보여줍니다.\n\n엔게디 동굴 사건에 이어 두 번째로 주어진 이 기회는 하나님께서 다윗의 믿음을 시험하시는 것이었습니다. 다윗은 사울의 창과 물병만을 가지고 나와 멀리 산꼭대기에서 외칩니다. 잠에서 깨어난 사울은 자신의 생명이 다윗의 손에 달려 있었음을 깨닫고 다시 한 번 자신의 잘못을 인정합니다. 그러나 이전과 마찬가지로 이는 일시적 감정에 불과했습니다.\n\n다윗의 선택은 단순한 정치적 계산이 아니었습니다. 그는 하나님께서 사울을 심판하실 때와 방법을 정하실 것임을 믿었습니다. "여호와께서 그를 치시리니 혹은 죽을 날이 이르거나 또는 전장에 나가서 망하리라"는 다윗의 말은 하나님의 시간표를 전적으로 신뢰하는 믿음의 고백입니다. 복수할 권리를 포기하고 하나님께 맡기는 것, 이것이 하나님의 사람이 걷는 길입니다. 다윗은 자기 손으로 왕위를 쟁취하는 대신 하나님의 때를 기다리는 믿음의 길을 선택했습니다.', E'오늘의 핵심\n다윗은 사울을 죽일 수 있는 두 번째 기회에도 하나님의 주권을 인정하며, 복수를 포기하고 하나님의 때를 기다리는 믿음을 보여줍니다.\n\n묵상 질문\n1. 내게 복수할 기회가 주어질 때, 나는 다윗처럼 하나님께 맡길 수 있나요?\n2. 하나님의 시간표를 기다리기 어려운 상황에서도 믿음으로 인내하고 있나요?\n3. 여호와의 기름 부음 받은 자를 존중하는 것처럼, 나는 하나님의 권위를 인정하며 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-02', E'회복과 새로운 땅 (에스겔 44장)', E'에스겔 44장', E'성전으로 돌아오신 여호와의 영광 앞에서 에스겔은 엎드릴 수밖에 없었습니다. 하나님께서는 동문으로 들어오신 후 그 문을 영원히 닫으라고 명하십니다. 이는 다시는 하나님께서 성전을 떠나지 않으시겠다는 약속의 상징입니다. 한 번 파괴되었던 성전, 하나님의 영광이 떠났던 그곳에 이제 영원한 임재를 선언하시는 것입니다.\n\n하나님은 과거 성전이 더럽혀진 이유를 분명히 지적하십니다. 할례받지 않은 이방인들이 성소에 들어와 있었고, 레위인들조차 우상을 따라 하나님을 떠났습니다. 그들은 자신들의 직분을 다른 이에게 맡기고 성전의 거룩함을 지키지 못했습니다. 하나님의 집이 시장터처럼 변질되었던 과거의 실패를 상기시키시는 것입니다.\n\n그러나 하나님의 은혜는 여기서도 빛납니다. 비록 레위인들이 죄를 지었지만, 완전히 버리지 않으시고 성전에서 수종드는 일을 맡기십니다. 다만 제사장 직분은 행할 수 없게 하심으로써 죄에는 분명한 결과가 따름을 보여주십니다. 은혜와 공의가 균형을 이루는 하나님의 다스리심을 봅니다.\n\n특별히 주목할 것은 사독의 자손들입니다. "이스라엘 족속이 그릇 행하여 나를 떠날 때에 사독의 자손 레위 사람 제사장들은 내 성소의 직분을 지켰은즉"(15절) 하나님은 그들의 충성을 잊지 않으셨습니다. 모두가 타락할 때 홀로 자리를 지킨 이들에게 가장 가까이에서 하나님을 섬기는 특권이 주어집니다.\n\n새 성전의 제사장들에게 주어진 규례들은 거룩함을 유지하기 위한 구체적 지침들입니다. 옷차림부터 결혼, 일상생활에 이르기까지 세세한 규정들이 주어집니다. 이는 단순한 율법주의가 아니라, 하나님과 백성 사이의 중보자로서 그들이 얼마나 거룩해야 하는지를 보여줍니다.\n\n오늘 우리도 왕 같은 제사장으로 부름받았습니다. 세상이 하나님을 떠날 때, 우리는 사독의 자손처럼 맡은 자리를 지키고 있습니까? 거룩함을 잃어버린 시대 속에서 구별된 삶을 살아가는 것, 그것이 이 시대 하나님의 제사장된 우리의 사명입니다.', E'오늘의 핵심\n하나님께서는 과거의 실패를 지적하시면서도 새 성전에서 충성된 자들에게 특별한 직분을 맡기시며, 거룩함을 지키는 구체적인 삶의 원칙을 제시하십니다.\n\n묵상 질문\n1. 모두가 타락할 때에도 자리를 지킨 사독의 자손처럼, 나는 어떤 영역에서 신실함을 지켜야 할까요?\n2. 하나님께서 내게 맡기신 직분과 자리를 다른 것에 위임하고 있지는 않나요?\n3. 거룩한 삶을 위해 오늘 내가 구별해야 할 구체적인 영역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-03', E'회복과 새로운 땅 (에스겔 45장)', E'에스겔 45장', E'에스겔서 45장은 회복된 이스라엘의 새로운 토지 분배와 예배 규정을 담고 있습니다. 포로로 끌려간 백성들에게 이 말씀은 단순한 미래의 청사진이 아니라, 하나님께서 여전히 그들과 함께하시며 새로운 시작을 준비하고 계신다는 확실한 약속이었습니다.\n\n하나님은 먼저 거룩한 구역을 구별하여 성소와 제사장들, 레위인들을 위한 땅을 정하십니다. 성전을 중심으로 한 이 새로운 배치는 하나님께서 다시 그들 가운데 거하실 것임을 보여줍니다. 또한 왕에게도 일정한 땅을 할당하시되, "나의 왕들이 다시는 내 백성을 압제하지 아니하리라"(겔 45:8)고 선언하십니다. 과거 왕들이 백성의 땅을 빼앗고 억압했던 역사가 반복되지 않도록 제도적 장치를 마련하신 것입니다.\n\n특히 주목할 점은 하나님께서 공정한 저울과 도량형을 강조하시는 부분입니다. 에바와 밧, 세겔의 정확한 기준을 제시하시며 경제 정의를 세우고자 하십니다. 예배와 일상, 성전과 시장이 분리되지 않고 하나님의 공의로 연결되어야 함을 가르치십니다. \n\n또한 군주가 백성을 위해 제사를 준비하는 책임을 지도록 규정하십니다. 명절과 안식일마다 번제와 소제를 갖추는 것이 왕의 의무가 됩니다. 권력은 섬김을 위해 존재한다는 하나님의 원칙이 여기에 담겨 있습니다.\n\n유월절과 초막절 규정을 상세히 제시하시는 하나님의 마음에는 과거 출애굽의 은혜를 잊지 않기를 바라시는 뜻이 담겨 있습니다. 포로 생활 중에도 하나님은 여전히 구원의 하나님이시며, 그들을 다시 이끌어내실 분이라는 메시지입니다. \n\n오늘 우리의 삶에도 하나님께서는 거룩한 구역을 정하기 원하십니다. 예배의 자리, 정의의 저울, 섬김의 리더십 - 이 모든 것이 하나님의 나라를 이루는 요소들입니다. 혼란한 시대 속에서도 하나님의 질서를 따라 살아가는 것, 그것이 회복을 준비하는 길입니다.', E'오늘의 핵심\n하나님께서는 새로운 이스라엘 공동체의 청사진을 제시하시며, 예배와 정의, 리더십의 올바른 질서를 회복시키겠다고 약속하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님께 구별하여 드려야 할 ''거룩한 구역''은 무엇일까요?\n2. 일상에서 실천할 수 있는 ''공정한 저울''의 정신은 어떤 모습일까요?\n3. 섬기는 리더십으로 나를 변화시키기 위해 오늘 무엇을 시작할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-04', E'회복과 새로운 땅 (에스겔 46장)', E'에스겔 46장', E'에스겔이 본 새 성전의 환상은 계속 이어집니다. 이번에는 성전 예배의 구체적인 규례들이 제시되는데, 특별히 안식일과 초하루의 예배, 그리고 군주와 백성이 드리는 제사의 규정이 상세하게 기록되어 있습니다. 바벨론 포로로 끌려가 성전 없이 지내야 했던 이스라엘 백성에게 이 말씀은 어떤 의미였을까요? 그것은 하나님께서 다시 그들과 함께하실 것이며, 예배의 질서가 회복될 것이라는 소망의 메시지였습니다.\n\n주목할 점은 예배의 중심에 ''군주''가 등장한다는 것입니다. 이 군주는 백성을 대표하여 하나님께 나아가되, 스스로 제사를 드리지는 못합니다. 제사장이 그를 위해 번제와 감사제를 드리고, 군주는 문 통로에서 예배합니다. 이는 왕권과 제사장직이 분명히 구별되어야 함을 보여줍니다. 과거 웃시야 왕이 제사장의 직무를 침범하다가 나병에 걸렸던 일을 기억한다면, 이러한 질서의 중요성을 더욱 깊이 이해할 수 있습니다.\n\n또한 백성들이 북문으로 들어온 자는 남문으로 나가고, 남문으로 들어온 자는 북문으로 나가도록 한 규정도 의미심장합니다. "들어온 문으로 도로 나가지 말고 그 몸이 앞으로 향한 대로 나갈지며"(겔 46:9)라는 말씀은 예배자가 하나님을 만난 후에는 결코 예전의 모습으로 돌아갈 수 없음을 상징적으로 보여줍니다. 참된 예배는 우리를 변화시키고 새로운 방향으로 나아가게 합니다.\n\n한편, 군주의 기업 상속에 관한 규정도 눈여겨볼 만합니다. 군주는 백성의 기업을 빼앗아서는 안 되며, 자기 아들에게 줄 것은 자기 산업으로만 해야 합니다. 이는 아합이 나봇의 포도원을 빼앗았던 과거의 악행이 반복되지 않도록 하는 안전장치입니다. 하나님의 나라에서는 권력자라 할지라도 약자의 권리를 침해할 수 없습니다.\n\n마지막으로 성전 뜰의 부엌에 대한 묘사가 나옵니다. 거룩한 제사와 함께 일상적인 음식 준비의 공간까지 세심하게 계획하신 하나님의 배려가 느껴집니다. 예배는 거룩한 의식만이 아니라 백성의 삶 전체를 아우르는 것임을 알 수 있습니다. 오늘 우리의 예배도 마찬가지입니다. 주일 예배당에서의 경건함이 월요일 일터에서의 정직함으로 이어질 때, 그것이 진정한 예배입니다.', E'오늘의 핵심\n에스겔이 본 새 성전의 예배 규례는 질서 있는 예배를 통해 하나님과 백성이 만나고, 그 만남이 삶의 변화로 이어져야 함을 보여줍니다.\n\n묵상 질문\n1. 나는 예배를 통해 어떤 변화를 경험하고 있나요? 들어온 문으로 되돌아가지 않고 앞으로 나아가고 있나요?\n2. 내가 가진 권한이나 영향력을 다른 사람의 유익을 위해 사용하고 있나요, 아니면 나의 욕심을 채우는 데 사용하고 있나요?\n3. 주일의 예배가 일상의 삶으로 어떻게 연결되어야 할까요? 오늘 실천할 수 있는 한 가지는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-06', E'회복과 새로운 땅 (에스겔 47장)', E'에스겔 47장', E'포로로 끌려간 에스겔에게 하나님께서 보여주신 새 성전의 환상은 절정을 향해 나아갑니다. 성전 문지방 밑에서 시작된 작은 물줄기가 점차 깊어져 마침내 헤엄쳐야 할 만큼 큰 강이 되는 장면은, 하나님의 생명력이 얼마나 풍성한지를 보여줍니다. 처음에는 발목에 오르던 물이 무릎에, 허리에, 그리고 마침내는 건널 수 없는 강이 됩니다. 이 점진적인 깊어짐은 하나님의 은혜가 우리 삶에 임하는 방식을 떠올리게 합니다.\n\n더욱 놀라운 것은 이 강물이 흘러가는 곳마다 일어나는 변화입니다. 죽음의 바다로 알려진 사해까지도 이 물이 이르면 살아나고, 고기가 번성하며, 어부들이 그물을 치게 됩니다. 강 좌우에는 열매가 끊이지 않는 나무들이 자라며, 그 잎은 치료하는 약이 됩니다. 성전에서 흘러나온 물이 온 땅에 생명과 치유, 풍요를 가져오는 것입니다.\n\n이어서 하나님께서는 회복될 이스라엘의 경계를 분명히 하십니다. 흥미롭게도 이 땅의 분배에는 이스라엘 백성뿐 아니라 그들 가운데 거하는 타국인들도 포함됩니다. "너희는 그 타국인을 본토에서 난 이스라엘 족속 같이 여기고"(겔 47:22)라는 말씀은 하나님의 은혜가 민족의 경계를 넘어섬을 보여줍니다.\n\n바벨론의 포로로 절망 가운데 있던 백성들에게 이 환상은 단순한 위로를 넘어 확실한 소망이었습니다. 지금은 비록 약속의 땅에서 쫓겨났지만, 하나님께서는 더 영광스러운 회복을 준비하고 계셨던 것입니다. 성전에서 흘러나오는 생명의 강은 오늘 우리에게도 동일하게 흐르고 있습니다. 메마른 우리의 영혼과 삶의 현장에 하나님의 생명수가 스며들어 새로운 생명력을 불어넣기를 갈망합니다.', E'오늘의 핵심\n성전에서 흘러나온 물이 온 땅에 생명을 가져오는 환상은, 하나님께서 주시는 은혜가 점진적으로 깊어지며 모든 것을 새롭게 한다는 약속입니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 은혜가 발목에서 시작해 점점 깊어진 경험이 있나요?\n2. 죽음의 바다 같은 내 삶의 영역이 하나님의 생명수로 회복될 수 있다고 믿으시나요?\n3. 하나님의 은혜가 ''타국인''처럼 소외된 이들에게까지 미친다는 말씀이 오늘 나에게 주는 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-07', E'회복과 새로운 땅 (에스겔 48장)', E'에스겔 48장', E'에스겔서의 대단원의 막을 내리는 48장은 회복된 이스라엘의 땅 분배와 새 예루살렘 성읍의 청사진을 보여줍니다. 포로로 끌려간 백성들에게 이 환상은 단순한 지도가 아니라, 하나님께서 여전히 그들을 당신의 백성으로 여기신다는 확실한 증거였습니다.\n\n각 지파에게 땅을 분배하시는 하나님의 모습은 여호수아 시대를 떠올리게 합니다. 한 가지 다른 점은 이제 모든 지파가 동일한 크기의 땅을 받는다는 것입니다. 과거의 불평등이나 차별 없이, 하나님 앞에서 모두가 동등한 상속자로 인정받습니다. 특별히 사독의 자손들은 "이스라엘 족속이 그릇될 때에... 그릇되지 아니하였느니라"(겔 48:11)는 평가와 함께 가장 거룩한 땅을 받습니다. 어두운 시대에도 신실함을 지킨 이들을 하나님은 기억하고 계셨던 것입니다.\n\n더욱 놀라운 것은 성읍의 새 이름입니다. ''여호와 삼마'' - ''여호와께서 거기 계시다''는 뜻입니다. 성전이 파괴되고 하나님의 영광이 떠났던 그 자리에, 이제 하나님께서 영원히 거하시겠다는 약속이 주어집니다. 포로 생활의 절망 속에서도 하나님은 결코 자기 백성을 포기하지 않으셨습니다.\n\n오늘 우리의 삶에도 무너진 것들이 있을 수 있습니다. 깨어진 관계, 좌절된 꿈, 실패한 계획들... 그러나 에스겔이 본 환상은 하나님께서 폐허 위에 새로운 질서를 세우시는 분임을 보여줍니다. 중요한 것은 사독의 자손들처럼 어두운 때에도 맡은 자리를 지키는 신실함입니다. 하나님은 그런 이들과 함께 새 역사를 쓰기 원하십니다. 오늘도 ''여호와 삼마'' - 하나님이 함께하시는 그 약속을 붙들고 살아갑시다.', E'오늘의 핵심\n에스겔이 본 새 예루살렘의 환상은 하나님께서 자기 백성과 영원히 함께 거하시겠다는 언약의 완성을 보여줍니다.\n\n묵상 질문\n1. 모든 지파에게 동등하게 땅을 분배하시는 하나님의 공평하심이 내 삶에는 어떻게 나타나고 있나요?\n2. 어두운 시대에도 신실함을 지킨 사독의 자손들처럼, 나는 지금 맡은 자리를 충실히 지키고 있나요?\n3. ''여호와 삼마'' - 하나님이 함께 계신다는 약속이 오늘 내게 주는 위로와 소망은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-08', E'바벨론 제국에서의 위인 (다니엘 1장)', E'다니엘 1장', E'유다가 바벨론에 의해 멸망하고 많은 백성이 포로로 끌려가는 참담한 역사가 펼쳐집니다. 바벨론 제국은 정복한 나라의 인재들을 선발하여 바벨론식 교육을 시킨 후, 그들의 고국을 다스리는 관리로 활용하는 정책을 펼쳤습니다. 이에 따라 유다의 왕족과 귀족 중에서 용모가 수려하고 지혜로운 소년들이 선발되었고, 그중에는 다니엘과 하나냐, 미사엘, 아사랴가 있었습니다.\n\n바벨론 왕궁에서의 교육은 단순한 학문 교육이 아니었습니다. 갈대아의 학문과 언어를 배우는 것은 물론, 왕의 음식과 포도주를 먹으며 바벨론의 문화에 완전히 동화되도록 하는 과정이었습니다. 심지어 그들의 이름마저 바벨론식으로 바뀌었습니다. 다니엘은 벨드사살로, 하나냐는 사드락으로, 미사엘은 메삭으로, 아사랴는 아벳느고로 개명되었습니다. 이는 그들의 정체성을 뿌리째 바꾸려는 시도였습니다.\n\n그러나 다니엘은 이런 상황에서 놀라운 결단을 내립니다. "뜻을 정하여 왕의 음식과 그가 마시는 포도주로 자기를 더럽히지 아니하리라"(단 1:8) 결심한 것입니다. 포로의 신분으로서 왕의 명령을 거역하는 것은 생명을 걸어야 하는 일이었습니다. 그럼에도 다니엘은 하나님께 대한 신앙의 순수함을 지키기로 결단했습니다.\n\n놀랍게도 하나님께서는 다니엘이 환관장에게 은혜와 긍휼을 얻도록 역사하셨습니다. 열흘간의 시험 기간을 거쳐, 채식과 물만으로 생활한 다니엘과 세 친구들의 얼굴은 왕의 진미를 먹은 다른 소년들보다 더욱 건강하고 윤택했습니다. 이는 단순히 음식의 문제가 아니라 하나님께서 그들의 신앙적 결단을 기뻐하시고 축복하신 결과였습니다.\n\n하나님께서는 이들에게 특별한 은사를 더하셨습니다. 모든 학문과 지혜에 뛰어나게 하셨고, 특별히 다니엘에게는 환상과 꿈을 해석하는 능력까지 주셨습니다. 왕이 시험해 본 결과, 그들의 지혜와 총명은 바벨론 전국의 박수와 술객보다 열 배나 뛰어났습니다. 포로로 끌려온 소년들이 오히려 제국의 중심에서 하나님의 영광을 드러내는 도구가 된 것입니다.', E'오늘의 핵심\n포로의 절망적 상황 속에서도 신앙의 순수함을 지키겠다는 다니엘의 결단은 하나님의 특별한 은혜와 축복으로 이어졌습니다.\n\n묵상 질문\n1. 신앙의 타협을 요구받는 상황에서 다니엘처럼 ''뜻을 정하는'' 결단이 필요한 영역은 무엇인가요?\n2. 하나님께서는 신앙을 지키려는 우리의 작은 결단에 어떻게 응답하시나요?\n3. 세상의 가치관에 동화되지 않고 하나님의 자녀로서의 정체성을 지키기 위해 무엇을 실천하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-09', E'바벨론 제국에서의 위인 (다니엘 2장)', E'다니엘 2장', E'느부갓네살 왕은 불안한 꿈으로 인해 잠을 이루지 못했습니다. 왕은 바벨론의 모든 지혜자들을 불러 꿈의 내용과 해석을 함께 요구하는 무리한 명령을 내렸습니다. 이는 단순히 꿈을 해석하는 것이 아니라 꿈 자체를 알아맞히라는 불가능한 요구였습니다. 갈대아 술사들이 "육체와 함께 살지 아니하는 신들 외에는 왕 앞에 그것을 보일 자가 없나이다"(단 2:11)라고 고백한 것처럼, 인간의 지혜로는 도저히 풀 수 없는 일이었습니다.\n\n이 위기의 순간에 다니엘은 왕에게 시간을 달라고 요청한 후 친구들과 함께 하나님께 간구했습니다. 그들의 기도는 단순히 목숨을 구하는 것이 아니라, 하늘에 계신 하나님의 긍휼하심을 구하는 것이었습니다. 하나님께서는 밤 환상으로 다니엘에게 왕의 꿈과 그 해석을 보여주셨습니다. 다니엘의 찬양 기도는 하나님이 역사의 주관자이시며, 왕들을 세우시고 폐하시는 분이심을 고백합니다.\n\n왕 앞에 선 다니엘은 먼저 인간의 지혜로는 이 일을 해결할 수 없음을 분명히 했습니다. 그리고 오직 하늘에 계신 하나님만이 은밀한 것을 나타내실 수 있다고 선포했습니다. 느부갓네살이 본 거대한 신상의 꿈은 앞으로 펼쳐질 세계 역사의 흐름을 보여주는 것이었습니다. 금으로 된 머리는 바벨론 제국을, 은으로 된 가슴과 팔은 메대-페르시아를, 놋으로 된 배와 넓적다리는 헬라 제국을, 쇠로 된 다리는 로마 제국을 상징했습니다.\n\n그러나 가장 중요한 것은 손대지 않은 돌이 모든 나라를 부수고 온 세계를 가득 채우는 장면이었습니다. 이것은 하나님께서 세우실 영원한 나라를 가리킵니다. 제국의 절정에서 느부갓네살이 받은 이 계시는 인간의 나라가 아무리 강대해도 결국은 무너지며, 오직 하나님의 나라만이 영원함을 보여줍니다. 포로로 잡혀온 다니엘을 통해 이방 왕에게 전해진 이 메시지는 고난 중에 있는 이스라엘 백성에게 큰 위로와 소망이 되었습니다.', E'오늘의 핵심\n하나님께서는 다니엘을 통해 인간 제국의 한계와 하나님 나라의 영원함을 계시하시며, 역사의 진정한 주관자가 누구인지를 선포하십니다.\n\n묵상 질문\n1. 내 삶의 불가능한 상황 속에서도 하나님께 지혜를 구하고 있나요?\n2. 다니엘처럼 위기를 기도의 기회로 삼는 믿음이 있습니까?\n3. 세상 권세가 아닌 하나님의 영원한 나라를 소망하며 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-10', E'시와 찬미 (시편 143장)', E'시편 143장', E'다윗의 마지막 시편으로 알려진 143편은 극심한 영적 고통 속에서 드리는 절박한 기도입니다. "원수가 내 영혼을 핍박하며 내 생명을 땅에 엎어서 나로 죽은 지 오랜 자 같이 나를 암흑 속에 두셨나이다"(시 143:3)라는 고백은 그가 처한 상황의 심각성을 보여줍니다. 영혼이 상하고 마음이 참담한 상태에서 다윗은 무덤에 내려가는 자처럼 느껴질 만큼 절망적인 순간을 경험하고 있습니다.\n\n그러나 다윗의 기도는 절망에 머물지 않습니다. 그는 옛날을 기억하며 하나님께서 행하신 일들을 묵상합니다. 과거에 경험한 하나님의 신실하심이 현재의 어둠 속에서도 희망의 근거가 됩니다. 마른 땅이 비를 갈망하듯 그의 영혼은 하나님을 향해 손을 펴며 간절히 사모합니다. 이는 단순한 도움 요청이 아니라 생명의 근원이신 하나님과의 교제를 갈망하는 영혼의 부르짖음입니다.\n\n특별히 주목할 것은 다윗이 구하는 것들입니다. 그는 아침에 주의 인자한 말씀을 듣기를 원하며, 다닐 길을 알게 해 달라고 간구합니다. 또한 하나님의 뜻을 행하도록 가르쳐 주시기를 구하며, 선하신 성령께서 공평한 땅으로 인도해 주시기를 요청합니다. 이는 단순히 위기에서 벗어나는 것을 넘어 하나님의 뜻을 따라 살아가고자 하는 성화의 열망을 보여줍니다.\n\n다윗은 자신을 "주의 종"이라 고백하며 시편을 마무리합니다. 극심한 고난 속에서도 하나님과의 관계를 포기하지 않고 오히려 더욱 깊이 의존하는 모습은, 고난이 우리를 하나님으로부터 멀어지게 하는 것이 아니라 더욱 가까이 이끄는 통로가 될 수 있음을 보여줍니다. 영혼의 어둔 밤을 지나는 모든 이들에게 이 시편은 소망의 기도가 됩니다.', E'오늘의 핵심\n극심한 영적 고통 속에서도 다윗은 하나님의 과거 행적을 기억하며 신실하신 하나님께 자신의 영혼을 맡기고, 그분의 뜻을 따라 살기를 간구합니다.\n\n묵상 질문\n1. 영혼이 상하고 마음이 참담할 때, 당신은 무엇을 기억하며 하나님께 나아가나요?\n2. 아침마다 하나님의 인자한 말씀을 듣기 위해 어떤 영적 훈련을 실천하고 있나요?\n3. 고난 속에서도 "주의 종"이라는 정체성을 붙잡는 것이 왜 중요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-11', E'시와 찬미 (시편 144장)', E'시편 144장', E'다윗의 시편 144편은 전쟁의 하나님을 찬양하는 노래로 시작하여 평화로운 일상의 축복을 갈망하는 기도로 마무리되는 독특한 구조를 보여줍니다. "나의 반석이신 여호와를 찬송하리로다 그가 내 손을 가르쳐 싸우게 하시며 손가락을 가르쳐 전쟁하게 하시는도다"(시 144:1)라는 고백은 수많은 전투를 치러온 전사 다윗의 경험에서 우러나온 신앙고백입니다. 그는 자신의 군사적 능력이나 전략이 아니라 하나님께서 가르쳐 주신 것임을 분명히 인정합니다.\n\n특별히 주목할 부분은 다윗이 하나님을 묘사하는 일곱 가지 호칭입니다. 사랑, 요새, 산성, 구원자, 방패로 표현되는 이 고백들은 모두 다윗이 실제 전쟁터에서 경험한 하나님의 보호하심을 담고 있습니다. 그런데 이어지는 구절에서 다윗은 놀라운 질문을 던집니다. "여호와여 사람이 무엇이기에 주께서 그를 알아 주시며 인생이 무엇이기에 그를 생각하시나이까"라는 이 물음은 창조주 하나님 앞에서 인간 존재의 보잘것없음을 깨달은 겸손한 고백입니다.\n\n시편의 후반부로 가면서 다윗의 기도는 전쟁에서의 승리를 넘어 일상의 평화로운 삶으로 확장됩니다. 자녀들이 건강하게 자라고, 곳간에 곡식이 가득하며, 양떼가 번성하고, 거리에 슬픈 부르짖음이 없는 평온한 삶의 모습을 그립니다. 이는 단순히 물질적 번영을 추구하는 것이 아니라, 하나님의 보호 아래에서 누리는 샬롬의 삶을 갈망하는 것입니다. 다윗은 이 모든 축복의 근원이 "여호와를 자기 하나님으로 삼는" 데 있음을 분명히 합니다. 전쟁의 승리도, 일상의 평화도 모두 하나님과의 올바른 관계에서 흘러나오는 것임을 우리에게 가르쳐 줍니다.', E'오늘의 핵심\n전쟁에서 보호하시고 일상에서 평화를 주시는 하나님을 자기 하나님으로 삼는 백성이야말로 진정으로 복된 백성입니다.\n\n묵상 질문\n1. 내 삶의 전투 속에서 하나님은 어떤 분으로 경험되고 있나요?\n2. 창조주 하나님 앞에서 나의 존재를 돌아볼 때 어떤 마음이 드나요?\n3. 하나님이 주시는 일상의 평화와 축복을 어떻게 누리고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-13', E'시와 찬미 (시편 145장)', E'시편 145장', E'다윗의 마지막 찬양시로 알려진 시편 145편은 하나님의 위대하심과 은혜로우심을 노래하는 장엄한 찬양입니다. "왕이신 나의 하나님이여 내가 주를 높이고 영원히 주의 이름을 송축하리이다"(145:1)라는 다윗의 선언은 단순한 의무감에서 나온 것이 아니라, 일평생 하나님을 경험한 자의 진실한 고백입니다.\n\n이 시편에서 다윗은 하나님의 속성을 두 가지 측면에서 균형 있게 제시합니다. 먼저 하나님의 위대하심과 권능을 선포합니다. 하나님의 위대하심은 측량할 수 없으며, 그분의 기이한 일들은 대대로 전해져야 합니다. 동시에 다윗은 하나님의 은혜와 긍휼을 강조합니다. 여호와는 모든 것을 선대하시고, 노하기를 더디하시며, 인자하심이 크신 분입니다.\n\n특별히 주목할 부분은 14절부터 나타나는 하나님의 구체적인 돌보심입니다. 하나님은 넘어지는 자들을 붙드시고, 비굴한 자들을 일으키시며, 때를 따라 먹을 것을 주시는 분입니다. 이는 추상적인 신학이 아니라 일상 속에서 경험하는 하나님의 실제적인 사랑입니다. 다윗은 왕이었지만, 그도 넘어지고 굶주리며 비굴해지는 순간들을 경험했고, 그때마다 하나님의 붙드심을 체험했습니다.\n\n이 시편의 절정은 하나님께서 "자기에게 간구하는 모든 자 곧 진실하게 간구하는 모든 자에게 가까이 하신다"는 약속입니다. 위대하신 하나님이 동시에 가까이 계신 하나님이라는 역설적 진리가 우리 신앙의 핵심입니다. 그래서 다윗은 자신의 입술뿐 아니라 "모든 육체가 그의 거룩하신 이름을 영원히 송축할지로다"라는 비전으로 시를 마무리합니다. 한 개인의 찬양이 온 피조물의 찬양으로 확대되는 것, 이것이 하나님을 아는 자의 소망입니다.', E'오늘의 핵심\n측량할 수 없이 위대하신 하나님은 동시에 넘어지는 자를 붙드시고 간구하는 자에게 가까이 하시는 은혜의 하나님이십니다.\n\n묵상 질문\n1. 하나님의 위대하심과 친밀하심을 동시에 경험한 적이 있나요? 그 경험이 당신의 기도 생활을 어떻게 변화시켰나요?\n2. 넘어지고 비굴해진 순간에 하나님의 붙드심을 경험했던 때를 기억해 보세요. 그 은혜를 누구와 나누시겠습니까?\n3. "모든 육체가 하나님을 송축하기를" 바라는 다윗의 비전이 당신의 일상에서 어떻게 실천될 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-14', E'시와 찬미 (시편 146장)', E'시편 146장', E'"할렐루야"로 시작하는 시편 146편은 우리가 진정으로 의지해야 할 대상이 누구인지를 분명하게 가르쳐 줍니다. 시인은 먼저 자신의 영혼에게 명령합니다. "내 영혼아 여호와를 찬양하라"(146:1). 이는 단순한 감정의 표현이 아니라, 생전과 평생에 걸친 결단의 선언입니다.\n\n시인은 우리에게 중요한 경고를 전합니다. 귀인들이나 인생을 의지하지 말라는 것입니다. 그 이유는 명확합니다. "그의 호흡이 끊어지면 흙으로 돌아가서 그 날에 그의 생각이 소멸하리로다"(146:4). 인간의 권력과 계획은 호흡과 함께 사라지는 것임을 상기시킵니다. 반면 "야곱의 하나님"을 도움으로 삼는 자는 복이 있다고 선포합니다. \n\n그렇다면 하나님은 어떤 분이신가요? 시편은 하나님의 성품을 구체적으로 보여줍니다. 천지 만물을 창조하신 분이 억눌린 자를 위해 정의로 심판하시고, 주린 자에게 먹을 것을 주시며, 갇힌 자에게 자유를 주십니다. 맹인의 눈을 여시고, 비굴한 자를 일으키시며, 의인을 사랑하십니다. 특별히 나그네와 고아와 과부 같은 사회적 약자를 보호하시는 하나님의 모습이 선명하게 드러납니다.\n\n이것이 바로 우리가 의지해야 할 하나님의 모습입니다. 권력자들이 자신의 이익을 위해 약자를 외면할 때, 하나님은 오히려 그들을 붙드십니다. 인간의 통치는 일시적이지만, 시온의 하나님은 영원히 다스리시고 대대로 통치하십니다. 그래서 시편은 다시 "할렐루야"로 끝납니다. 이런 하나님이 우리의 하나님이시기에, 우리는 인생의 어떤 상황에서도 찬양할 수 있습니다.', E'오늘의 핵심\n인간의 도움은 일시적이지만, 천지를 창조하시고 약자를 돌보시는 하나님의 통치는 영원합니다. 이 하나님을 의지하는 자가 진정으로 복된 사람입니다.\n\n묵상 질문\n1. 나는 지금 누구의 도움을 더 의지하고 있나요? 사람의 권력인가요, 하나님의 능력인가요?\n2. 억눌린 자와 갇힌 자를 돌보시는 하나님의 마음이 내 삶과 섬김에 어떻게 반영되고 있나요?\n3. 영원히 다스리시는 하나님께 대한 찬양이 내 일상의 어려움 속에서도 계속될 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-15', E'시와 찬미 (시편 147장)', E'시편 147장', E'시편 147편은 바벨론 포로에서 돌아온 백성들이 부르는 감격의 찬양입니다. "여호와께서 예루살렘을 세우시며 이스라엘의 흩어진 자들을 모으시며"(147:2)라는 고백은 단순한 찬양이 아니라, 포로 생활의 아픔을 겪고 돌아온 자들의 생생한 증언입니다. 하나님은 무너진 성벽을 재건하실 뿐 아니라, 상심한 마음과 상처 입은 영혼까지 싸매어 주시는 분입니다.\n\n시편 기자는 하나님의 위대하심을 우주적 차원에서 바라봅니다. 무수한 별들의 수효를 세시고 각각의 이름을 부르시는 하나님의 무궁한 지혜는, 동시에 겸손한 자를 붙드시고 악인을 엎드러뜨리시는 세밀한 돌보심으로 나타납니다. 창조주의 광대하심과 목자의 섬세하심이 하나로 어우러지는 놀라운 고백입니다.\n\n특별히 주목할 것은 하나님께서 기뻐하시는 것이 무엇인가 하는 점입니다. 말의 힘이나 사람의 다리가 억센 것, 즉 인간의 힘과 능력이 아니라, "자기를 경외하는 자들과 그의 인자하심을 바라는 자들"(147:11)을 기뻐하신다는 선언은 하나님과의 관계에서 가장 중요한 것이 무엇인지를 분명히 보여줍니다.\n\n시편 후반부에서는 자연 현상을 통해 하나님의 주권을 노래합니다. 눈과 서리, 우박을 내리시고 또 그것들을 녹이시는 하나님의 말씀의 능력은, 이스라엘에게 율례와 규례를 주신 특별한 은혜와 연결됩니다. 창조의 질서를 다스리시는 그 말씀이 곧 이스라엘을 인도하시는 생명의 말씀입니다. 이 특권을 깨달은 백성의 입에서 "할렐루야"가 터져 나오는 것은 너무나 자연스러운 일입니다.', E'오늘의 핵심\n포로에서 돌아온 백성들의 찬양은 상처를 싸매시고 흩어진 자를 모으시는 하나님의 섬세한 돌보심과, 온 우주를 다스리시는 그분의 위대하심을 동시에 노래합니다.\n\n묵상 질문\n1. 상심한 마음과 상처를 싸매시는 하나님의 치유를 경험한 적이 있나요?\n2. 힘과 능력이 아니라 경외함과 인자하심을 바라는 마음을 기뻐하시는 하나님 앞에서 나는 무엇을 의지하고 있나요?\n3. 하나님의 말씀이 나의 삶을 다스리시는 특권을 어떻게 누리고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-16', E'시와 찬미 (시편 148장)', E'시편 148장', E'시편 148편은 온 우주가 참여하는 장엄한 찬양의 교향곡입니다. 시인은 하늘에서부터 땅까지, 천사들로부터 모든 피조물에 이르기까지 창조주 하나님을 찬양하도록 초대합니다. 이 찬양의 부름은 단순한 권면이 아니라, 피조물의 존재 목적 자체가 창조주를 높이는 것임을 선포하는 것입니다.\n\n먼저 하늘의 영역에서 찬양이 시작됩니다. 천사들과 하늘의 군대, 해와 달과 별들, 그리고 하늘 위의 물들까지 하나님을 찬양하도록 부름받습니다. 시인은 이들이 찬양해야 하는 이유를 분명히 제시합니다: "그가 명령하시므로 지음을 받았음이로다"(148:5). 모든 천체와 하늘의 존재들은 하나님의 말씀으로 창조되었기에, 그들의 존재 자체가 창조주의 능력과 영광을 증거합니다.\n\n이어서 찬양의 무대는 땅으로 옮겨집니다. 바다의 용들과 자연 현상들, 산과 나무들, 짐승과 새들이 모두 이 찬양의 합창에 동참합니다. 특별히 주목할 것은 인간 사회의 모든 계층이 포함된다는 점입니다. 왕들과 백성들, 고관들과 재판관들, 젊은이와 노인, 남녀노소 모두가 여호와의 이름을 찬양하도록 부름받습니다. 이는 하나님 앞에서 모든 인간의 신분과 나이의 구별이 무의미함을 보여줍니다.\n\n시편은 찬양의 이유를 분명히 밝힙니다: "그의 이름이 홀로 높으시며 그의 영광이 땅과 하늘 위에 뛰어나심이로다"(148:13). 오직 하나님만이 참된 찬양을 받으시기에 합당한 분이십니다. 그리고 이 우주적 찬양의 중심에는 "그를 가까이 하는 백성 이스라엘 자손"이 있습니다. 하나님께서는 자기 백성의 뿔을 높이시고 그들과 특별한 언약 관계를 맺으셨습니다.\n\n이 시편은 우리에게 찬양이 단지 예배의 한 부분이 아니라 피조물의 본질적 사명임을 일깨워줍니다. 해와 달이 빛을 비추는 것이 그들의 찬양이듯, 우리의 삶 전체가 창조주를 높이는 찬양이 되어야 합니다. "할렐루야"로 시작하고 끝나는 이 시편은, 우리의 하루도 그렇게 하나님을 찬양하며 시작하고 마쳐야 함을 가르쳐줍니다.', E'오늘의 핵심\n온 우주 만물이 창조주 하나님을 찬양하도록 부름받았으며, 특별히 하나님의 백성된 우리는 그분의 영광을 선포하는 찬양의 삶을 살아야 합니다.\n\n묵상 질문\n1. 자연만물이 하나님을 찬양한다는 것을 일상에서 어떻게 경험하고 있나요?\n2. 나이와 신분을 초월한 모든 사람이 하나님을 찬양해야 한다는 부르심이 내게 어떤 도전을 주나요?\n3. 오늘 나의 삶이 하나님께 드리는 찬양이 되기 위해 무엇을 바꾸어야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-17', E'시와 찬미 (시편 149장)', E'시편 149장', E'시편 149편은 "할렐루야"로 시작하는 찬양시 연작의 네 번째 시편으로, 하나님의 백성이 드리는 찬양의 본질과 능력을 보여줍니다. "새 노래로 여호와께 노래하며 성도의 모임 가운데에서 찬양할지어다"(149:1)라는 권면으로 시작되는 이 시편은 개인적 찬양을 넘어 공동체가 함께 드리는 예배의 중요성을 강조합니다. 새 노래는 단순히 새로운 곡조를 의미하는 것이 아니라, 하나님께서 행하신 새로운 일들에 대한 신선한 감격과 응답을 담은 찬양입니다.\n\n이스라엘이 창조주 하나님으로 인해 즐거워하고, 시온의 주민이 그들의 왕으로 인해 기뻐하는 모습은 하나님과 백성 사이의 특별한 관계를 드러냅니다. 춤과 소고와 수금으로 드리는 찬양은 온 몸과 마음을 다한 예배의 표현입니다. 특히 주목할 것은 하나님께서 "겸손한 자를 구원으로 아름답게 하신다"(149:4)는 선언입니다. 세상이 무시하는 낮은 자들을 하나님은 구원의 영광으로 장식하십니다.\n\n시편의 후반부는 독특한 이중성을 보여줍니다. 성도들의 입에는 하나님을 향한 찬양이, 손에는 두 날 가진 칼이 있다는 표현은 영적 전쟁의 실재를 암시합니다. 이는 복수심에 찬 폭력이 아니라, 하나님의 공의를 실현하는 거룩한 사명을 의미합니다. 찬양은 단순한 감정의 표현이 아니라 악의 세력을 무너뜨리는 영적 무기입니다.\n\n"성도들은 영광 중에 즐거워하며 그들의 침상에서 기쁨으로 노래할지어다"(149:5)라는 구절은 찬양이 공적 예배에만 국한되지 않음을 보여줍니다. 침상이라는 가장 사적인 공간에서도 기쁨의 노래가 터져 나올 때, 그것은 찬양이 우리 삶의 본질이 되었음을 증거합니다. 하나님의 백성에게 주어진 이러한 영광스러운 특권은 단순한 종교적 의무가 아니라, 구원받은 자의 자연스러운 반응이며 영적 권세의 표현입니다.', E'오늘의 핵심\n하나님께서는 겸손한 자를 구원으로 아름답게 하시며, 찬양은 성도에게 주어진 영광스러운 특권이자 영적 권세의 표현입니다.\n\n묵상 질문\n1. 나의 찬양은 습관적인 반복인가요, 아니면 하나님의 새로운 일하심에 대한 신선한 응답인가요?\n2. 공적 예배뿐 아니라 일상의 삶 속에서도 기쁨의 노래가 나오고 있나요?\n3. 하나님께서 겸손한 나를 구원으로 아름답게 하신다는 약속이 오늘 나에게 어떤 위로와 소망을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-18', E'시와 찬미 (시편 150장)', E'시편 150장', E'시편 전체의 대미를 장식하는 150편은 짧지만 강렬한 찬양의 교향곡입니다. 열세 번이나 반복되는 "찬양하라"는 명령은 단순한 반복이 아니라 점진적으로 확장되는 찬양의 물결을 보여줍니다. 시편은 "복 있는 사람"(1:1)으로 시작하여 "할렐루야"로 끝나는데, 이는 하나님과 동행하는 삶의 궁극적 목적지가 찬양임을 가르쳐 줍니다.\n\n"그의 성소에서"와 "권능의 궁창에서"(150:1)라는 표현은 찬양의 장소가 지상의 성전과 하늘의 영역을 아우름을 보여줍니다. 하나님의 임재는 특정 공간에 제한되지 않으며, 온 우주가 그분을 찬양하는 성전입니다. 이어지는 구절들은 찬양의 이유를 "그의 능하신 행동"과 "지극히 위대하심"(150:2)으로 요약합니다. 우리가 찬양하는 것은 하나님께서 베푸신 은혜 때문만이 아니라 그분의 본질적인 위대하심 때문입니다.\n\n시편 기자는 나팔, 비파, 수금, 소고, 춤, 현악, 퉁소, 제금 등 당시 알려진 모든 악기를 동원하여 찬양할 것을 권면합니다. 이는 우리가 가진 모든 은사와 재능, 방법을 총동원하여 하나님을 높여야 함을 의미합니다. 특별히 "소고 치며 춤추어"(150:4)라는 표현은 찬양이 단순한 소리의 문제가 아니라 온 몸과 마음을 다한 예배의 행위임을 보여줍니다.\n\n마지막 절인 "호흡이 있는 자마다 여호와를 찬양할지어다"(150:6)는 시편 전체의 결론이자 모든 피조물의 존재 이유를 선포합니다. 숨을 쉬는 것 자체가 하나님의 선물이며, 그 호흡으로 우리가 해야 할 가장 숭고한 일은 창조주를 찬양하는 것입니다. 이렇게 시편은 인생의 모든 희로애락을 거쳐 결국 찬양으로 수렴되는 신앙의 여정을 보여주며, 우리를 영원한 할렐루야의 합창으로 초대합니다.', E'오늘의 핵심\n시편의 대단원은 온 우주와 모든 피조물이 각자의 방법으로 하나님을 찬양하는 장엄한 교향곡으로 마무리되며, 호흡이 있는 자마다 창조주를 찬양하는 것이 존재의 목적임을 선포합니다.\n\n묵상 질문\n1. 당신의 삶에서 하나님을 찬양할 수 있는 고유한 방법과 은사는 무엇인가요?\n2. 일상의 호흡 하나하나가 하나님의 선물임을 인식할 때, 당신의 하루는 어떻게 달라질까요?\n3. 시편이 탄식으로 시작하여 찬양으로 끝나듯, 당신의 고난도 찬양으로 변화될 수 있음을 믿으시나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-20', E'제국 변천의 중심에 서서 (다니엘 5장)', E'다니엘 5장', E'바빌론 제국의 마지막 날이 다가오고 있었습니다. 벨사살 왕이 천 명의 귀족들을 위해 성대한 잔치를 열었을 때, 그는 아버지 느부갓네살이 예루살렘 성전에서 탈취해 온 거룩한 기명들을 가져오게 합니다. 왕과 귀족들은 하나님의 거룩한 그릇으로 술을 마시며 금, 은, 구리, 쇠, 나무, 돌로 만든 우상들을 찬양했습니다. 이는 단순한 음주 행위가 아니라 하나님의 거룩함에 대한 의도적인 모독이었습니다.\n\n바로 그 순간, 사람의 손가락이 나타나 왕궁 벽에 글자를 쓰기 시작합니다. 방금 전까지 술에 취해 있던 왕의 얼굴빛이 창백하게 변하고 무릎이 떨렸습니다. 바빌론의 모든 지혜자들이 소집되었지만 아무도 그 글을 해석하지 못합니다. 왕비의 조언으로 다니엘이 부름을 받았을 때, 그는 왕의 상급을 거절하면서도 하나님의 메시지를 분명하게 전합니다.\n\n다니엘은 먼저 느부갓네살의 교훈을 상기시킵니다. 그가 교만하여 왕위에서 쫓겨나 들짐승과 같이 되었다가 "지극히 높으신 하나님이 사람 나라를 다스리시며 자기의 뜻대로 누구든지 그 자리에 세우시는 줄"(단 5:21)을 깨달은 이야기를 들려줍니다. 그런데 벨사살은 이 모든 것을 알면서도 마음을 낮추지 않고 오히려 하늘의 주재보다 자신을 높였다는 것입니다.\n\n벽에 쓰인 ''메네 메네 데겔 우바르신''이라는 글은 하나님의 심판을 선포하는 것이었습니다. 하나님께서 왕의 나라를 끝내시고, 왕을 저울에 달아보니 부족했으며, 그 나라가 메대와 바사에게 넘어갈 것이라는 뜻이었습니다. 그날 밤 벨사살은 죽임을 당하고 메대 사람 다리오가 바빌론을 차지합니다. 역사의 주관자이신 하나님께서는 교만한 제국의 시간표를 친히 정하시고 심판하셨습니다.', E'오늘의 핵심\n하나님께서는 자신을 높이고 거룩함을 모독하는 교만한 권력자들을 심판하시며, 역사의 흥망성쇠를 주관하시는 분이심을 보여주십니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 높아진 것들은 무엇이며, 어떻게 겸손히 낮출 수 있을까요?\n2. 하나님의 거룩한 것들을 일상적으로 대하며 경외심을 잃어버린 부분은 없나요?\n3. 역사를 주관하시는 하나님을 신뢰하며 오늘 하루를 어떻게 살아갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-21', E'제국 변천의 중심에 서서 (다니엘 6장)', E'다니엘 6장', E'메대 사람 다리오가 바빌론을 정복하고 새로운 통치 체제를 구축하면서, 120명의 고관과 세 명의 총리를 임명합니다. 놀랍게도 포로로 잡혀온 유다인 다니엘이 그 총리 중 한 사람이 되었고, 그의 탁월한 행정 능력으로 인해 왕은 그를 전국을 다스리는 최고 총리로 세우려 합니다. \n\n다니엘의 승진을 시기한 관리들은 그를 제거할 구실을 찾으려 했지만, 그의 충성됨과 흠 없는 삶 앞에서 아무것도 발견할 수 없었습니다. 결국 그들은 다니엘의 신앙생활을 표적으로 삼아 교묘한 함정을 만들어냅니다. 왕 외에는 어떤 신이나 사람에게도 기도하지 못하게 하는 조서를 왕에게 제안한 것입니다.\n\n다니엘은 왕의 도장이 찍힌 조서를 알면서도 평소와 같이 하루 세 번 예루살렘을 향해 창문을 열고 무릎을 꿇어 기도합니다. 소년 시절부터 지켜온 이 신앙의 습관은 이제 그의 생명을 위협하는 올무가 되었지만, 그는 하나님께 대한 충성을 포기하지 않습니다. \n\n사자 굴에 던져진 다니엘을 위해 오히려 왕이 밤새 금식하며 잠을 이루지 못하는 모습은 참으로 역설적입니다. 이방 왕이 하나님의 종을 위해 간절히 염려하고 있는 것입니다. 새벽에 왕이 급히 달려가 부르짖을 때, 다니엘은 "나의 하나님이 이미 그의 천사를 보내어 사자들의 입을 봉하셨으므로"(단 6:22)라고 대답합니다. \n\n하나님의 기적적인 구원을 목격한 다리오 왕은 온 나라에 조서를 내려 다니엘의 하나님을 경외하도록 명령합니다. 포로로 잡혀온 한 사람의 변함없는 신앙이 이방 제국 전체에 하나님의 이름을 드높이게 한 것입니다. 다니엘의 일관된 신앙생활은 어떤 정치적 변화나 위협 속에서도 하나님의 주권을 증거하는 강력한 도구가 되었습니다.', E'오늘의 핵심\n변함없는 기도의 습관을 지킨 다니엘을 통해 하나님께서는 이방 제국에 당신의 살아계심을 증거하시고, 모든 민족이 하나님을 경외하도록 역사하십니다.\n\n묵상 질문\n1. 나의 신앙생활은 주변 상황에 관계없이 일관성을 유지하고 있나요?\n2. 신앙 때문에 손해를 감수해야 할 때, 나는 어떤 선택을 하고 있나요?\n3. 내 삶의 어떤 영역에서 다니엘처럼 꾸준한 기도의 습관을 만들어갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-22', E'소망의 반석', E'베드로전서 1장', E'AD 64년, 네로 황제가 로마 대화재 사건의 책임을 그리스도인들에게 전가하면서 기독교 박해가 급속히 가중되었습니다. 이런 상황 속에서 베드로는 교회의 장래를 염려하여 성도들에게 소망을 주기 위해 편지를 보냅니다. 베드로의 편지는 고난과 핍박을 견디고 있는 성도들에게 힘과 격려를 주는 글로 시작하고 있습니다. 미래에 대한 강한 소망과 비전이 있는 사람에게는 현재의 시련과 고난을 오히려 기쁨으로 감당할 수 있는 힘이 있습니다. 베드로는 이 사실을 강조하며 예수님 안에서의 소망을 이야기합니다. 시험과 근심은 잠깐이지만 예수님께서 다시 오시는 날, 그들에게 주어질 칭찬과 영광과 존귀는 그 모든 괴로움을 상쇄할 것이라고 말합니다.\n무거운 핍박과 고난 속에서도, 베드로는 성도들에게 오히려 진심으로 기뻐하라고 말합니다. 시련의 기간은 그때가 지난 후에 있을 영원한 즐거움에 비교되지 않습니다. 또한 이 시련의 시간은 믿음을 평가하는 시험이자 훈련의 과정입니다. 그리고 베드로는 주님 오시는 그날까지, 마음의 허리를 동이고 근신하여 거룩하게 살아야 한다고 당부합니다.', E'오늘의 핵심\n시험과 근심은 잠깐이지만 예수님께서 다시 오시는 날 성도들에게 주어질 영광과 존귀는 그 모든 괴로움을 넘어서는 영원한 것입니다.\n\n묵상 질문\n예수님 안의 소망이 없어도 상관없다고 생각했던 적이 있으신가요?\n지금 내 인생에서 현재의 시련을 기쁨으로 바꿀 소망이 무엇인지 알고 계신가요?\n오늘 하나님의 소망을 더 깊이 마음에 품고 살기로 결단할 수 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-23', E'시편 3편 압살롬의 반역', E'사무엘하 15장', E'압살롬이 아버지 다윗에 대한 반역의 기발을 높이 치켜듭니다. 오랜 시간 동안 꾸준히 예루살렘과 헤브론을 오가며 민심을 자신의 것으로 만들 만큼 압살롬의 계획은 치밀했습니다. 그는 아버지의 오랜 동지이자 전략가였던 아히도벨까지 포섭하여 만만치 않은 세력을 이루었습니다. 결국 다윗은 압살롬이 예루살렘에 도착하기 전에 황급히 성을 빠져나와야 했습니다. 압살롬은 예루살렘 성을 장악하고 왕으로 등극합니다. 그러나 아직 반역이 완전히 성공한 것은 아닙니다.\n다윗의 도피길에 동행하기 위해 레위 사람들과 제사장들이 하나님의 궤를 메고 쫓아옵니다. 그러나 다윗은 하나님의 궤를 돌려보내고 제사장 사독과 그의 아들 아히마아스, 제사장 아비아달과 그의 아들 요나단을 예루살렘에 남겨 놓음으로써 하나님을 향한 믿음과 뒷일을 준비하는 정치가의 노련함을 보여줍니다. 그때 압살롬 세력에 아히도벨이 가담하였다는 청천벽력 같은 소식이 들리자 다윗은 자신의 신하 가운데 아히도벨과 맞먹을 정도로 노련한 정치인 후새를 압살롬 진영에 거짓 투항시킵니다. 당시 최고의 모사였던 아히도벨, 그리고 다윗의 제안으로 거짓 투항한 후새, 이제 이들의 전략 싸움이 압살롬 반역의 성패를 결정하게 됩니다.', E'오늘의 핵심\n치밀하게 준비된 압살롬의 반역에 놀란 다윗은 황급히 예루살렘을 빠져나오면서도 믿음 가운데 반역군에 대항할 전략을 세웁니다.\n\n묵상 질문\n하나님은 다윗이 실패하고 도망칠 때도 버리지 않으셨을까요?\n내가 누군가에게 상처를 받았을 때 어떻게 대응하고 있나요?\n다윗처럼 어려움 속에서도 하나님을 신뢰하는 마음으로 기도하겠다는 다짐이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-24', E'남북분열과 여로보암의 길 (열왕기상 12장)', E'열왕기상 12장', E'다윗 왕조의 찬란했던 영광이 솔로몬 시대를 거치며 서서히 빛을 잃어가고 있었습니다. 솔로몬이 남긴 정치적 유산은 백성들에게는 무거운 멍에였고, 이제 그의 아들 르호보암이 왕위를 계승하는 순간 이스라엘의 운명이 갈림길에 서게 됩니다. 세겜에 모인 온 이스라엘 백성이 새 왕에게 간절히 호소합니다. "왕의 아버지가 우리의 멍에를 무겁게 하였으나 왕은 이제 왕의 아버지가 우리에게 시킨 고역과 매우 무거운 멍에를 가볍게 하소서"(왕상 12:4). 이것은 단순한 정치적 요구가 아니라 생존을 위한 절박한 외침이었습니다.\n\n르호보암은 먼저 아버지의 신하였던 노인들에게 자문을 구합니다. 그들의 조언은 지혜로웠습니다. 왕이 백성을 섬기는 자가 되어 좋은 말로 대답한다면, 백성들이 영원히 왕의 종이 될 것이라는 충고였습니다. 그러나 르호보암은 이 지혜로운 조언을 버리고 자신과 함께 자란 젊은이들의 의견을 따릅니다. 그들의 조언은 더욱 강압적으로 백성을 다스리라는 것이었고, 르호보암은 포악한 말로 백성들에게 대답합니다. \n\n이 어리석은 결정의 결과는 즉각적이었습니다. 온 이스라엘이 "우리가 다윗과 무슨 관계가 있느냐"라고 외치며 각자의 장막으로 돌아갔고, 통일왕국은 남북으로 분열되고 맙니다. 성경은 이 일이 "여호와께로 말미암아 난 것"이라고 기록합니다. 하나님께서는 솔로몬의 우상숭배에 대한 심판으로 이미 예고하신 일을 르호보암의 어리석음을 통해 이루신 것입니다.\n\n북왕국의 왕이 된 여로보암 역시 처음에는 하나님의 선택을 받은 사람이었습니다. 그러나 권력을 유지하려는 욕심이 그를 잘못된 길로 인도합니다. 백성들이 예루살렘 성전에 예배하러 가면 마음이 르호보암에게로 돌아갈 것을 두려워한 여로보암은 벧엘과 단에 금송아지를 만들어 세웁니다. 더 나아가 레위인이 아닌 보통 백성으로 제사장을 삼고, 하나님께서 정하신 절기마저 임의로 바꿔버립니다. 하나님의 뜻보다 정치적 계산을 앞세운 그의 선택은 북이스라엘을 우상숭배의 길로 이끄는 씨앗이 되었습니다.', E'오늘의 핵심\n르호보암의 어리석은 결정으로 통일왕국이 분열되고, 여로보암은 정치적 욕심으로 북이스라엘을 우상숭배의 길로 인도하여 하나님의 백성이 신앙의 본질에서 멀어지게 합니다.\n\n묵상 질문\n1. 지혜로운 조언을 거부하고 자신의 뜻대로 행하려는 내 모습은 없나요?\n2. 두려움 때문에 하나님의 뜻을 왜곡하거나 타협하고 있지는 않나요?\n3. 오늘 나에게 필요한 겸손한 섬김의 자세는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-25', E'남북분열과 여로보암의 길 (열왕기상 13장)', E'열왕기상 13장', E'하나님께서는 벧엘의 금송아지 제단에서 분향하는 여로보암에게 심판의 메시지를 전하기 위해 유다에서 한 선지자를 보내십니다. 이 하나님의 사람은 제단을 향해 예언합니다. 훗날 요시야라는 왕이 나타나 이 제단에서 분향하는 제사장들을 제물로 바치고 사람의 뼈를 그 위에서 사를 것이라는 무서운 심판의 말씀이었습니다. 그 징조로 제단이 갈라지고 재가 쏟아질 것이라고 선포하자, 여로보암은 분노하여 그를 잡으라고 명령합니다. 그러나 선지자를 향해 편 왕의 손이 즉시 말라버리고, 예언한 대로 제단이 갈라지며 재가 쏟아집니다.\n\n두려움에 사로잡힌 여로보암은 자신을 위해 기도해 달라고 간청하고, 하나님의 사람이 기도하자 왕의 손이 회복됩니다. 왕은 감사의 표시로 그를 왕궁에 초대하여 대접하려 하지만, 하나님의 사람은 단호히 거절합니다. 하나님께서 이곳에서는 떡도 먹지 말고 물도 마시지 말며, 왔던 길로 되돌아가지도 말라고 명하셨기 때문입니다.\n\n그런데 벧엘에 사는 한 늙은 선지자가 이 소식을 듣고 그를 뒤쫓아가 집으로 초대합니다. 하나님의 사람이 하나님의 명령을 이유로 거절하자, 늙은 선지자는 거짓말로 그를 속입니다. 천사가 자신에게 나타나 그를 데려와 대접하라고 했다는 것입니다. 결국 하나님의 사람은 속아서 그의 집에서 음식을 먹게 됩니다.\n\n식사 중에 여호와의 말씀이 늙은 선지자에게 임하여, 하나님의 명령을 어긴 하나님의 사람에게 심판을 선포합니다. 그의 시체가 조상들의 묘실에 들어가지 못할 것이라는 말씀이었습니다. 돌아가는 길에 사자가 나타나 그를 물어 죽이지만, 신기하게도 사자는 시체를 먹지도 않고 나귀를 해치지도 않은 채 그냥 서 있었습니다. 늙은 선지자는 그의 시체를 수습하여 자신의 묘실에 장사하며, 자신이 죽거든 그 옆에 묻어달라고 유언합니다. 그가 선포한 심판의 말씀이 반드시 이루어질 것을 확신했기 때문입니다.\n\n이 모든 일을 보고도 여로보암은 악한 길에서 돌이키지 않고 오히려 더욱 완고해졌습니다. 일반 백성 중에서 자원하는 사람이면 누구든지 산당의 제사장으로 삼는 죄악을 계속했고, 이로 인해 여로보암의 집은 멸망의 길로 들어서게 됩니다.', E'오늘의 핵심\n하나님의 말씀에 대한 순종은 타협할 수 없는 절대적인 것이며, 불순종은 반드시 심판을 가져온다는 엄중한 교훈을 보여줍니다.\n\n묵상 질문\n1. 하나님의 명령을 어기게 만드는 그럴듯한 유혹이 내 삶에도 있지 않나요?\n2. 표적을 보고도 회개하지 않는 여로보암의 완고함이 나에게도 있지는 않나요?\n3. 하나님의 말씀에 절대적으로 순종하기 위해 오늘 무엇을 결단하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-27', E'남북분열과 여로보암의 길 (열왕기상 14장)', E'열왕기상 14장', E'하나님의 부르심으로 북이스라엘의 초대 왕이 된 여로보암은 점차 교만해져 하나님의 명령을 거역했습니다. 이제 그 죄의 결과가 그의 가정에 나타나기 시작합니다. 아들 아비야가 병들자 여로보암은 아내를 변장시켜 선지자 아히야에게 보냅니다. 바로 그 아히야는 과거 여로보암에게 왕이 될 것을 예언했던 선지자였습니다. 그러나 늙어서 눈이 어두워진 아히야는 하나님의 계시로 모든 것을 알고 있었습니다.\n\n아히야를 통해 전해진 하나님의 메시지는 준엄했습니다. 하나님께서는 여로보암을 백성 중에서 높여 왕으로 세우시고 다윗의 나라를 찢어 그에게 주셨지만, 그는 다윗처럼 전심으로 하나님을 따르지 않았습니다. 오히려 금송아지 우상을 만들어 백성들로 하여금 죄를 짓게 했습니다. 그 결과 여로보암의 집안은 완전히 멸망하게 될 것이며, 병든 아들 아비야는 어머니가 집에 돌아가는 즉시 죽게 될 것이라고 선포됩니다. 그나마 이 아이만이 여로보암 집안에서 유일하게 하나님을 향한 선한 마음을 품었기에 정상적인 장례를 치를 수 있다는 것이 유일한 위로였습니다.\n\n한편 남유다의 르호보암도 그의 아버지 솔로몬의 잘못된 길을 그대로 따라갔습니다. 유다 백성들은 산당과 우상과 아세라 상을 세우며 가나안 족속들의 가증한 일들을 본받아 행했습니다. 그 결과 르호보암 제5년에 애굽 왕 시삭이 침입하여 성전과 왕궁의 모든 보물을 약탈해 갔습니다. 솔로몬이 만든 금 방패들까지 모두 빼앗기자 르호보암은 그 대신 놋 방패를 만들어야 했습니다. 이는 한때 영화롭던 솔로몬 왕국이 얼마나 초라하게 전락했는지를 상징적으로 보여줍니다.\n\n하나님께서는 다윗과 같은 신실한 왕을 원하셨지만, 북이스라엘의 여로보암과 남유다의 르호보암은 모두 하나님을 떠나 우상숭배의 길로 갔습니다. 그들이 하나님의 은혜를 저버린 결과는 가정의 비극과 나라의 쇠락으로 나타났습니다.', E'오늘의 핵심\n하나님을 떠나 우상을 섬긴 여로보암과 르호보암의 선택은 가정의 비극과 나라의 쇠락이라는 쓰라린 결과를 가져왔습니다.\n\n묵상 질문\n1. 여로보암이 아내를 변장시켜 보낸 것은 무엇을 두려워했기 때문일까요?\n2. 하나님께서 주신 은혜와 책임을 내가 어떻게 감당하고 있나요?\n3. 금 방패가 놋 방패로 바뀐 것처럼, 내 삶에서 잃어버린 영광은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-28', E'미래의 일들 (다니엘 10장)', E'다니엘 10장', E'고레스 왕 제삼년, 이스라엘 백성의 귀환이 이루어진 지 삼 년이 지났습니다. 예루살렘에서는 성전 재건이 시작되었지만 주변국들의 방해로 어려움을 겪고 있던 시기였습니다. 이런 상황에서 다니엘에게 큰 전쟁에 관한 환상이 보입니다. 그는 세 이레 동안 금식하며 간절히 기도했습니다. 힛데겔 강가에서 기도하던 다니엘에게 세마포 옷을 입은 한 천사가 나타났고, 그 영광스러운 모습 앞에서 다니엘은 기력을 잃고 쓰러졌습니다.\n\n천사는 떨고 있는 다니엘을 일으켜 세우며 놀라운 말씀을 전합니다. "큰 은총을 받은 사람 다니엘아 두려워하지 말라"(단 10:11). 하나님께서는 다니엘이 기도하기 시작한 첫날부터 그의 기도를 들으셨다는 것입니다. 다만 바사 왕국의 군주가 이십일 일 동안 천사를 막았고, 천사장 미가엘이 도와주어서야 다니엘에게 올 수 있었습니다. 이는 우리가 알지 못하는 영적 전쟁이 하늘에서 일어나고 있음을 보여줍니다.\n\n천사는 다니엘에게 마지막 날에 이스라엘 백성이 당할 일을 알려주러 왔다고 말합니다. 이 환상의 무게에 짓눌려 다니엘은 다시 힘을 잃지만, 천사는 그를 만지며 "평안하라 강건하라"고 격려합니다. 하나님께서는 어려운 시기를 지나는 백성들에게 미래의 일들을 미리 보여주심으로써, 현재의 고난이 하나님의 계획 안에 있음을 알려주십니다. 비록 지금은 성전 재건이 중단되고 적대적인 상황이 계속되지만, 하나님께서는 자기 백성을 잊지 않으셨습니다. 오히려 그들을 위해 하늘에서 영적 전쟁이 벌어지고 있었던 것입니다.', E'오늘의 핵심\n하나님께서는 우리의 기도를 첫날부터 들으시며, 보이지 않는 영적 영역에서도 우리를 위해 일하고 계십니다. 어려운 상황 속에서도 "큰 은총을 받은 사람"이라 부르시며 평안과 강건함을 주십니다.\n\n묵상 질문\n1. 다니엘의 기도가 첫날부터 응답받았는데 왜 삼 주가 걸렸을까요? 내 기도의 응답이 더딜 때 어떤 마음을 가져야 할까요?\n2. 하나님이 다니엘을 "큰 은총을 받은 사람"이라고 부르셨습니다. 어려운 상황에서도 나는 하나님의 은총 받은 자녀임을 기억하고 있나요?\n3. 천사가 "평안하라 강건하라"고 반복해서 말했습니다. 오늘 내게 필요한 하나님의 위로는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-29', E'미래의 일들 (다니엘 11장)', E'다니엘 11장', E'다니엘이 받은 환상 중에서도 11장은 매우 구체적이고 상세한 미래의 역사를 보여주고 있습니다. 바사 제국 이후 헬라 제국의 등장과 분열, 그리고 남방 왕과 북방 왕 사이의 끊임없는 전쟁이 펼쳐집니다. 이 예언은 놀라울 정도로 정확하게 역사 속에서 성취되었는데, 알렉산더 대왕의 죽음 이후 그의 제국이 네 부분으로 나뉘고, 특히 이집트의 프톨레마이오스 왕조(남방 왕)와 시리아의 셀레우코스 왕조(북방 왕) 사이의 전쟁이 계속되었던 역사가 그대로 담겨 있습니다.\n\n본문은 단순히 정치적 격변만을 다루는 것이 아닙니다. 하나님께서는 이 모든 역사의 소용돌이 속에서도 자신의 백성을 주목하고 계십니다. 특히 주목할 부분은 32절의 말씀입니다. "오직 자기의 하나님을 아는 백성은 강하여 용맹을 떨치리라." 세상의 권력자들이 속임수와 폭력으로 자기 뜻을 관철시키려 할 때, 하나님을 아는 백성은 다른 종류의 강함을 보여줍니다. 그것은 무력이 아닌 신앙의 용기요, 권모술수가 아닌 진리를 향한 헌신입니다.\n\n본문은 또한 하나님의 백성이 겪게 될 고난도 숨기지 않습니다. 지혜로운 자들이 칼날과 불꽃과 사로잡힘을 당하며, 많은 이들이 몰락할 것이라고 예언합니다. 그러나 이 고난은 무의미한 것이 아닙니다. 35절은 이것이 "연단을 받아 정결하게 되며 희게 되어" 가는 과정임을 보여줍니다. 하나님의 섭리 안에서는 고난조차도 그의 백성을 정결케 하는 도구가 됩니다.\n\n이 복잡하고 어두운 역사의 파노라마를 보여주시는 이유는 무엇일까요? 그것은 하나님께서 역사의 주관자이심을 분명히 보여주기 위함입니다. 인간의 눈에는 혼돈과 우연의 연속처럼 보이는 역사도, 하나님의 관점에서는 정확한 계획과 목적 아래 진행되고 있습니다. "아직 정한 기한이 남았음이라"(35절)는 말씀은 모든 것이 하나님의 시간표 안에서 움직이고 있음을 확증해 줍니다.', E'오늘의 핵심\n역사의 모든 격변 속에서도 하나님은 자신의 백성을 주목하시며, 고난을 통해서라도 그들을 정결케 하시고 끝까지 보호하십니다.\n\n묵상 질문\n1. 세상의 권력이 요동칠 때에도 "자기의 하나님을 아는 백성"으로서 나는 어떤 강함을 가질 수 있을까요?\n2. 내가 겪는 시련이 하나님의 연단의 과정일 수 있다면, 지금 내 삶의 어려움을 어떻게 바라봐야 할까요?\n3. "아직 정한 기한이 남았다"는 하나님의 시간표를 신뢰하며, 오늘 내가 붙들어야 할 약속은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-09-30', E'미래의 일들 (다니엘 12장)', E'다니엘 12장', E'고레스 왕 제3년, 다니엘은 미래에 대한 환상을 보며 큰 근심에 빠져 금식하며 기도했습니다. 세계 열강들 사이의 전쟁과 하나님의 백성이 당할 환난을 미리 보았기 때문입니다. 이제 다니엘서의 마지막 장에서 하나님은 그 모든 환난 너머에 있을 궁극적인 구원과 소망을 보여주십니다.\n\n하나님께서는 먼저 개국 이래로 없던 환난의 때가 올 것이라고 말씀하십니다. 그러나 그 환난의 때에도 "네 백성 중 책에 기록된 모든 자가 구원을 받을 것이라"(단 12:1)는 약속을 주십니다. 이는 하나님의 백성이 어떤 환난 속에서도 버림받지 않으며, 하나님의 구원 계획 안에 있음을 확증하는 말씀입니다.\n\n특별히 다니엘서는 구약에서 부활에 대해 가장 명확하게 언급하는 본문 중 하나입니다. 땅의 티끌 가운데서 자는 자들이 깨어나 영생을 받는 자와 영원한 수치를 당할 자로 나뉘게 될 것을 보여줍니다. 또한 지혜 있는 자들과 많은 사람을 의로 인도한 자들이 별과 같이 영원토록 빛날 것이라는 약속도 주어집니다. 이는 현재의 고난이 영원한 영광과 비교할 수 없음을 일깨워줍니다.\n\n다니엘이 이 모든 환상의 의미를 다 깨닫지 못하여 "이 모든 일의 결국이 어떠하겠나이까" 묻자, 하나님은 이 말씀을 마지막 때까지 간수하고 봉함하라고 하십니다. 그리고 환난의 때에 많은 사람이 연단을 받아 정결케 될 것이며, 지혜 있는 자는 깨달을 것이라 말씀하십니다.\n\n다니엘서의 마지막 말씀은 "너는 가서 마지막을 기다리라"는 것입니다. 평안히 쉬다가 끝날에는 자기 몫을 누리게 될 것이라는 약속과 함께 주어진 이 명령은, 현재의 어려움 속에서도 인내하며 소망 중에 기다려야 함을 가르쳐줍니다. 하나님의 구원 역사는 반드시 완성될 것이며, 그의 백성은 영원한 생명과 영광에 참여하게 될 것입니다.', E'오늘의 핵심\n다니엘서는 개국 이래 없던 환난이 올 것을 예고하면서도, 하나님의 백성이 구원받을 것과 부활의 소망, 그리고 영원한 영광의 약속으로 마무리됩니다.\n\n묵상 질문\n1. 환난의 때에도 "책에 기록된 자"는 구원받는다는 약속이 오늘 나에게 어떤 위로와 확신을 주나요?\n2. "지혜 있는 자"와 "많은 사람을 의로 인도한 자"가 별과 같이 빛난다는 말씀을 묵상할 때, 내 삶의 우선순위는 어떻게 재정립되어야 할까요?\n3. "가서 마지막을 기다리라"는 말씀처럼, 현재의 어려움 속에서도 평안함을 누리며 소망 중에 기다릴 수 있는 비결은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-01', E'성전 건축의 기초를 놓다 (에스라 3장)', E'에스라 3장', E'일곱째 달이 되었습니다. 예루살렘에 도착한 귀환 공동체가 가장 먼저 한 일은 하나님의 제단을 세우는 것이었습니다. 대제사장 예수아와 총독 스룹바벨의 인도로 백성들은 모세의 율법에 기록된 대로 제단을 만들고 번제를 드리기 시작합니다. 70년의 포로 생활 동안 중단되었던 예배가 다시 시작된 것입니다. \n\n귀환 공동체는 주변 민족들을 두려워하면서도 제단을 세우고 아침저녁으로 번제를 드렸습니다. 초막절을 지키고, 정해진 절기마다 제사를 드리며, 자원하는 예물을 바쳤습니다. 비록 성전의 기초도 놓지 못한 상황이었지만, 그들에게는 먼저 하나님께 예배드리는 일이 우선이었습니다.\n\n이듬해 둘째 달, 드디어 성전 재건 공사가 시작됩니다. 스룹바벨과 예수아를 중심으로 모든 백성이 힘을 모았고, 이십 세 이상의 레위인들이 공사를 감독했습니다. 건축자들이 성전의 기초를 놓을 때, 제사장들은 예복을 입고 나팔을 불었으며, 레위인들은 제금을 들고 다윗이 정한 규례대로 여호와를 찬송했습니다.\n\n"주는 지극히 선하시므로 그의 인자하심이 이스라엘에게 영원하시도다"(스 3:11)라는 찬양이 울려 퍼졌습니다. 그러나 이 감격의 순간에도 복잡한 감정이 교차했습니다. 젊은 세대는 기쁨으로 크게 함성을 질렀지만, 솔로몬 성전의 영광을 기억하는 노인들은 초라한 기초를 보며 대성통곡했습니다. 기쁨의 함성과 슬픔의 통곡이 뒤섞여 멀리까지 들렸습니다.\n\n하나님의 백성이 예배를 회복하는 모습은 우리에게 중요한 교훈을 줍니다. 그들은 어려운 환경 속에서도, 성전 건물이 없는 상황에서도 먼저 제단을 세우고 예배를 드렸습니다. 이것이 바로 신앙 공동체가 회복되는 출발점이었습니다.', E'오늘의 핵심\n포로에서 돌아온 백성들은 성전 건물보다 먼저 제단을 세우고 예배를 회복했으며, 기초를 놓으며 하나님의 인자하심을 찬양했습니다.\n\n묵상 질문\n1. 어려운 상황 속에서도 예배를 우선순위에 두는 신앙을 가지고 있나요?\n2. 과거의 영광에 얽매이지 않고 현재 하나님이 행하시는 일에 감사하고 있나요?\n3. 우리 공동체가 회복해야 할 예배의 본질은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-02', E'성전 건축의 기초를 놓다 (에스라 4장)', E'에스라 4장', E'귀환 공동체가 성전 재건의 기초를 놓자, 그 땅에 살고 있던 대적들이 나타나기 시작합니다. 이들은 앗수르 왕 에살핫돈 시대에 북이스라엘 멸망 후 사마리아 지역으로 이주된 이방인들과 그 후손들이었습니다. 그들은 스룹바벨과 족장들에게 접근하여 함께 성전을 건축하자고 제안합니다. 겉으로는 같은 하나님을 섬긴다고 주장했지만, 실상은 여호와 신앙과 이방 종교를 혼합한 혼합주의 신앙을 가진 사람들이었습니다.\n\n스룹바벨과 예수아는 단호하게 거절합니다. 하나님의 성전은 순수한 신앙 공동체에 의해 건축되어야 했기 때문입니다. 이 거절로 인해 대적들의 본심이 드러납니다. 그들은 유다 백성의 손을 약하게 하여 건축을 방해하고, 페르시아 관리들에게 뇌물을 주어 성전 건축 계획을 막습니다. 더 나아가 아닥사스다 왕에게 거짓 보고서를 올려 귀환 공동체가 성전이 아닌 성벽을 재건하여 반역을 꾀한다고 모함합니다.\n\n대적들의 교묘한 전략은 효과를 거둡니다. 페르시아 왕은 예루살렘의 과거 역사를 조사하고, 이 도시가 왕들에게 반역했던 전력이 있음을 확인한 후 공사 중단 명령을 내립니다. 르훔과 심새는 왕의 조서를 받자마자 예루살렘으로 급히 달려가 권력으로 공사를 중단시킵니다. 이렇게 하나님의 성전 재건 사업은 다리오 왕 2년까지 약 16년간 중단되고 맙니다.\n\n이 과정은 하나님의 일을 할 때 만나게 되는 영적 전투의 실상을 보여줍니다. 대적들은 처음에는 협력을 가장하여 접근하고, 거절당하면 직접적인 방해와 정치적 모함으로 하나님의 일을 막으려 합니다. 그러나 하나님께서는 이 모든 방해에도 불구하고 당신의 뜻을 이루어 가십니다. 중단된 성전 건축은 하나님께서 정하신 때에 학개와 스가랴 선지자를 통해 다시 시작될 것입니다.', E'오늘의 핵심\n하나님의 성전 재건을 방해하는 대적들의 교묘한 전략으로 공사가 중단되지만, 이는 하나님의 일을 하는 과정에서 겪게 되는 영적 전투의 한 단면입니다.\n\n묵상 질문\n1. 순수한 신앙을 지키기 위해 때로는 단호한 거절이 필요한 순간이 있지 않을까요?\n2. 하나님의 일을 방해하는 세력들 앞에서 낙심하지 않으려면 무엇이 필요할까요?\n3. 중단된 것처럼 보이는 하나님의 일도 하나님의 때에 다시 시작될 것을 믿고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-04', E'하나님은 사랑이시다 (요한일서 1장)', E'요한일서 1장', E'요한은 예수님의 열두 제자 가운데 가장 나이 어린 제자였지만, 이제는 초대교회를 책임지는 중요한 위치에서 교회를 이끄는 지도자가 되었습니다. 그는 생명의 말씀이신 예수 그리스도를 직접 보고, 듣고, 손으로 만졌던 증인으로서 이 편지를 씁니다. 요한이 전하는 복음의 핵심은 영원한 생명이신 예수 그리스도께서 우리에게 나타나셨다는 것입니다. 아버지와 함께 계시던 그분이 역사 속으로 들어오셔서 우리와 함께 거하셨습니다.\n\n요한이 이 편지를 쓰는 목적은 분명합니다. 그가 경험한 예수 그리스도를 전함으로써 읽는 이들도 하나님 아버지와 그의 아들 예수 그리스도와 사귐을 갖게 하려는 것입니다. 이 사귐은 단순한 종교적 관계가 아니라 생명의 교제이며, 이를 통해 충만한 기쁨을 누리게 됩니다.\n\n"하나님은 빛이시라 그에게는 어둠이 조금도 없으시다"(요일 1:5)는 선언은 요한일서 전체를 관통하는 핵심 메시지입니다. 빛이신 하나님과 사귐을 가진다는 것은 우리도 빛 가운데 행해야 함을 의미합니다. 그런데 우리는 여전히 연약하여 죄를 짓습니다. 요한은 이런 우리의 실존을 정직하게 인정합니다. 죄가 없다고 주장하는 것은 자기기만이며 하나님을 거짓말쟁이로 만드는 것입니다.\n\n그러나 여기에 놀라운 은혜가 있습니다. 우리가 죄를 자백할 때, 미쁘시고 의로우신 하나님께서 우리 죄를 사하시고 모든 불의에서 깨끗하게 하십니다. 예수 그리스도의 보혈은 빛 가운데 행하는 우리를 계속해서 정결케 하는 능력이 됩니다. 이것이 바로 빛이신 하나님과 어둠에 있는 우리 사이에 놓인 은혜의 다리입니다.', E'오늘의 핵심\n빛이신 하나님과의 참된 사귐은 우리가 빛 가운데 행할 때 가능하며, 연약하여 넘어질지라도 정직한 자백을 통해 예수님의 보혈로 깨끗함을 받을 수 있습니다.\n\n묵상 질문\n1. 나는 정말 하나님과 사귐이 있다고 확신할 수 있나요? 그 증거는 무엇인가요?\n2. 내 삶에서 아직도 어둠 가운데 숨기고 있는 죄는 없나요?\n3. 예수님의 보혈의 능력을 날마다 경험하며 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-05', E'하나님은 사랑이시다 (요한일서 2장)', E'요한일서 2장', E'요한은 교회 공동체를 향해 간절한 마음으로 편지를 씁니다. 그의 목적은 분명합니다. 신자들이 죄를 범하지 않도록 돕는 것입니다. 그러나 동시에 요한은 우리의 연약함을 알고 있습니다. 그래서 만일 누가 죄를 범하더라도 낙심하지 말라고 권면합니다. 왜냐하면 "아버지 앞에서 우리에게 대언자가 있으니 곧 의로우신 예수 그리스도"(요일 2:1)이시기 때문입니다. 예수님은 우리뿐만 아니라 온 세상의 죄를 위한 화목제물이 되셨습니다.\n\n요한은 진정한 그리스도인의 표지가 무엇인지 분명하게 제시합니다. 그것은 하나님의 계명을 지키는 것입니다. 말로만 하나님을 안다고 하면서 그분의 계명을 지키지 않는다면, 그것은 거짓말하는 것이라고 요한은 단호하게 말합니다. 특히 형제 사랑의 계명을 강조하면서, 빛 가운데 있다고 하면서도 형제를 미워하는 자는 여전히 어둠에 있다고 경고합니다. 형제를 사랑하는 것이야말로 빛 가운데 거하는 증거입니다.\n\n요한은 세상을 사랑하지 말라고 권면합니다. 육신의 정욕, 안목의 정욕, 이생의 자랑은 모두 아버지께로부터 온 것이 아니라 세상으로부터 온 것입니다. 이 세상과 그 정욕은 지나가지만, 오직 하나님의 뜻을 행하는 자는 영원히 거합니다. \n\n마지막 때가 가까워질수록 적그리스도의 영이 활동합니다. 예수께서 그리스도이심을 부인하고, 아버지와 아들을 부인하는 자들이 나타납니다. 그러나 성령의 기름부음을 받은 신자들은 진리 안에 굳게 서 있습니다. 요한은 처음부터 들은 복음의 진리를 굳게 붙잡고, 주 안에 거하라고 권면합니다. 이는 주께서 다시 오실 때 담대함을 얻어 부끄럽지 않게 하려는 것입니다.', E'오늘의 핵심\n그리스도인의 정체성은 계명을 지키며 형제를 사랑하는 삶으로 나타나며, 세상의 정욕을 따르지 않고 하나님의 뜻을 행하는 것입니다.\n\n묵상 질문\n1. 내가 진정으로 하나님을 아는 사람인지 어떻게 확인할 수 있을까요?\n2. 형제를 미워하면서도 빛 가운데 있다고 착각하고 있지는 않나요?\n3. 세상의 정욕과 하나님의 뜻 사이에서 나는 무엇을 선택하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-06', E'하나님은 사랑이시다 (요한일서 3장)', E'요한일서 3장', E'요한은 노년의 사도로서 교회 공동체에 남기는 가장 중요한 메시지를 전하고 있습니다. 그것은 바로 하나님의 자녀된 정체성과 그에 따른 삶의 방식에 관한 가르침입니다. "보라 아버지께서 어떠한 사랑을 우리에게 베푸사 하나님의 자녀라 일컬음을 받게 하셨는가"(요일 3:1)라는 감격어린 외침으로 시작되는 이 장은, 하나님의 압도적인 사랑이 우리의 신분과 삶을 어떻게 변화시키는지를 보여줍니다.\n\n하나님의 자녀가 된다는 것은 단순한 호칭의 변화가 아닙니다. 그것은 존재 자체의 변화이며, 삶의 방향과 내용이 완전히 달라지는 것을 의미합니다. 요한은 하나님의 자녀와 마귀의 자녀를 구별하는 분명한 표지가 있다고 가르칩니다. 그것은 의를 행하는 것과 형제를 사랑하는 것입니다. 특별히 형제 사랑의 문제는 이론이나 감정의 차원이 아니라 실천의 차원에서 다루어집니다.\n\n가인과 아벨의 이야기를 통해 요한은 미움이 곧 살인임을 밝힙니다. 형제를 미워하는 것은 여전히 사망에 머물러 있는 증거라고 단호히 말합니다. 반면 예수님께서 우리를 위해 목숨을 버리신 것처럼, 형제를 위해 목숨을 버리는 사랑이야말로 참된 사랑의 본질입니다. 이 사랑은 말과 혀로만 하는 것이 아니라 행함과 진실함으로 나타나야 합니다. 가진 재물로 궁핍한 형제를 돕는 것, 이것이 하나님의 사랑이 우리 안에 거하는 증거입니다.\n\n요한은 우리 마음이 우리를 책망할 때가 있어도 하나님은 우리 마음보다 크시다는 위로의 말씀을 전합니다. 이는 연약함에도 불구하고 계속해서 사랑의 삶을 살아가도록 격려하는 것입니다. 하나님의 계명은 예수 그리스도를 믿고 서로 사랑하는 것으로 요약됩니다. 이 계명을 지킬 때 우리는 주 안에 거하고 주님도 우리 안에 거하시게 됩니다. 성령께서 이 사실을 우리에게 확증해 주십니다.', E'오늘의 핵심\n하나님의 자녀 된 우리의 정체성은 형제를 향한 구체적인 사랑의 실천으로 나타나며, 이것이 우리가 생명 가운데 거하는 증거입니다.\n\n묵상 질문\n1. 나는 하나님의 자녀라는 정체성을 어떻게 일상에서 살아내고 있나요?\n2. 말과 혀로만이 아니라 행함과 진실함으로 사랑해야 할 형제는 누구인가요?\n3. 내 마음이 나를 책망할 때, 더 크신 하나님의 사랑을 어떻게 경험하셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-07', E'하나님은 사랑이시다 (요한일서 4장)', E'요한일서 4장', E'요한일서 4장은 거짓 영과 참 영을 분별하는 기준을 제시하면서, 하나님의 사랑이 우리 신앙의 본질임을 깊이 있게 전달합니다. 초대교회 당시 많은 거짓 교사들이 예수님의 성육신을 부인하며 교회를 혼란에 빠뜨렸습니다. 요한은 이에 대해 분명한 기준을 제시합니다. "예수 그리스도께서 육체로 오신 것을 시인하는 영마다 하나님께 속한 것이요"(요일 4:2)라고 선포하며, 성육신의 진리가 참된 신앙의 시금석임을 가르칩니다.\n\n그러나 요한의 관심은 단순히 교리적 분별에만 머물지 않습니다. 그는 즉시 사랑의 주제로 넘어가며, 참된 영성의 증거가 사랑임을 보여줍니다. 하나님의 사랑은 추상적인 개념이 아니라 독생자를 세상에 보내신 구체적인 행동으로 나타났습니다. 이 사랑은 우리가 먼저 하나님을 사랑해서가 아니라, 하나님이 먼저 우리를 사랑하사 화목제물로 그 아들을 보내신 데서 시작됩니다.\n\n요한은 이 하나님의 선행적 사랑을 경험한 자들에게 당연한 응답을 요구합니다. 그것은 서로 사랑하는 것입니다. 보이지 않는 하나님을 사랑한다고 하면서 보이는 형제를 미워하는 것은 거짓말이라고 단호하게 말합니다. 참된 하나님 사랑은 반드시 형제 사랑으로 구체화되어야 합니다.\n\n특별히 주목할 것은 "온전한 사랑이 두려움을 내쫓는다"는 말씀입니다. 심판에 대한 두려움, 관계에 대한 두려움, 미래에 대한 두려움 - 이 모든 것이 하나님의 완전한 사랑을 깨닫고 그 안에 거할 때 사라집니다. 하나님의 사랑 안에 거하는 자는 담대함을 얻게 됩니다. 이것이 웨슬리가 강조한 ''완전한 사랑''의 은혜입니다.', E'오늘의 핵심\n하나님의 선행적 사랑을 깨달은 자는 형제 사랑으로 응답하며, 이 온전한 사랑 안에서 모든 두려움을 극복하고 담대한 신앙인으로 살아갑니다.\n\n묵상 질문\n1. 내가 따르는 영이 진리의 영인지 어떻게 분별하고 있나요?\n2. 하나님이 먼저 나를 사랑하셨다는 진리가 내 삶을 어떻게 변화시켰나요?\n3. 형제를 사랑하지 못하게 하는 내 안의 두려움은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-08', E'하나님은 사랑이시다 (요한일서 5장)', E'요한일서 5장', E'요한일서는 노년의 사도 요한이 초대교회 성도들에게 보낸 사랑의 편지입니다. 특별히 5장에서 요한은 그리스도인의 승리하는 삶의 비밀을 밝혀줍니다. 그 핵심은 예수님이 하나님의 아들이심을 믿는 믿음에 있습니다. "예수께서 하나님의 아들이심을 믿는 자가 아니면 세상을 이기는 자가 누구냐"(요일 5:5)라는 수사적 질문은 이 진리를 강력하게 선포합니다.\n\n요한은 예수님께서 물과 피로 오신 분이라고 증언합니다. 이는 예수님의 세례(물)와 십자가의 죽음(피)을 가리키는 것으로, 그분의 공생애 시작부터 완성까지를 아우릅니다. 성령께서는 이 모든 것의 참됨을 증거하십니다. 이러한 삼중 증거 - 성령과 물과 피 - 는 예수님이 그리스도이심을 확증하는 하나님의 완전한 증언입니다.\n\n믿음의 결과는 영생입니다. 요한은 하나님의 아들을 믿는 자에게는 생명이 있다고 단언합니다. 이 영생은 미래에 받을 소망이 아니라 현재 소유하고 있는 확실한 실재입니다. 그래서 믿는 자들은 담대함을 가지고 하나님께 나아갈 수 있으며, 그분의 뜻에 따라 구하는 것은 무엇이든지 응답받을 수 있다는 확신을 갖게 됩니다.\n\n하나님께로부터 난 자는 계속해서 죄 가운데 머물지 않습니다. 이는 인간의 노력이 아닌 하나님의 보호하심 때문입니다. 악한 자가 만지지 못하도록 지켜주시는 분은 하나님께로부터 나신 자, 곧 예수 그리스도이십니다. 요한은 편지를 마무리하며 예수님이 참 하나님이시요 영생이시라고 선포합니다. 그리고 마지막으로 우상을 멀리하라는 권면을 덧붙입니다. 참되신 하나님을 알고 그 안에 거하는 자들에게 우상은 더 이상 필요하지 않기 때문입니다.', E'오늘의 핵심\n예수님을 하나님의 아들로 믿는 믿음이 세상을 이기는 승리의 비결이며, 이 믿음 안에서 우리는 영생을 소유하고 하나님의 보호하심 가운데 담대히 살아갑니다.\n\n묵상 질문\n1. 나는 예수님이 하나님의 아들이심을 진정으로 믿고 고백하며 살아가고 있나요?\n2. 하나님께 담대히 나아가 그분의 뜻대로 구하는 기도를 드리고 있나요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 우상은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-09', E'오므리 왕조와 엘리야의 사역 (열왕기상 18장)', E'열왕기상 18장', E'기근이 시작된 지 삼 년째, 하나님은 엘리야에게 아합 앞에 나타나라고 명하십니다. 그동안 엘리야의 예언대로 비가 내리지 않았고, 아합은 엘리야를 찾아 온 나라를 뒤졌지만 찾을 수 없었습니다. 흥미롭게도 하나님은 왕궁 관리인 오바댜를 통해 엘리야와 아합의 만남을 주선하십니다. 오바댜는 이세벨이 여호와의 선지자들을 학살할 때 백 명을 굴에 숨겨 보호했던 신실한 신앙인이었습니다. 악한 왕궁 한복판에서도 하나님을 경외하는 사람이 있었다는 사실은 우리에게 위로와 도전을 줍니다.\n\n아합은 엘리야를 만나자마자 "이스라엘을 괴롭게 하는 자"라고 비난합니다. 그러나 엘리야는 단호하게 진짜 문제는 여호와의 명령을 버리고 바알을 따른 왕실에 있음을 지적합니다. 그리고 갈멜 산에서 누가 참 하나님인지 증명하자고 제안합니다. \n\n갈멜 산에 모인 백성 앞에서 엘리야는 "너희가 어느 때까지 둘 사이에서 머뭇머뭇 하려느냐"라고 일갈합니다. 당시 백성들은 여호와도 섬기고 바알도 섬기는 혼합주의에 빠져 있었습니다. 바알의 선지자 450명이 아침부터 저녁까지 춤추고 소리치며 자해까지 했지만 아무 응답이 없었습니다. 반면 엘리야는 무너진 여호와의 제단을 열두 돌로 다시 쌓고, 제물에 물을 세 번이나 부은 뒤 조용히 기도했습니다. "주께서 이스라엘 중에서 하나님이신 것과... 이 백성에게 주 여호와는 하나님이신 것과 주는 그들의 마음을 되돌이키심을 알게 하옵소서"(왕상 18:36-37). \n\n그러자 하늘에서 불이 내려와 번제물과 나무뿐 아니라 돌과 물까지 삼켜버렸습니다. 이 압도적인 광경을 본 백성들은 비로소 "여호와 그는 하나님이시로다"라고 고백합니다. 갈멜 산의 대결은 단순한 종교적 시위가 아니라, 혼합주의에 빠진 백성의 마음을 하나님께로 돌이키려는 하나님의 사랑의 표현이었습니다.', E'오늘의 핵심\n갈멜 산에서 하나님은 압도적인 불의 응답으로 자신이 유일한 참 하나님이심을 증명하시고, 머뭇거리던 백성들의 마음을 돌이키셨습니다.\n\n묵상 질문\n1. 악한 환경 속에서도 신앙을 지켰던 오바댜처럼, 내가 속한 곳에서 하나님을 경외하며 살아가고 있나요?\n2. 내 삶에 여호와도 섬기고 세상도 섬기는 ''영적 혼합주의''는 없는지 돌아볼 때입니다. 무엇을 결단해야 할까요?\n3. 엘리야의 기도처럼 하나님이 내 삶의 유일한 주인이심을 드러내는 기도를 드리고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-11', E'오므리 왕조와 엘리야의 사역 (열왕기상 19장)', E'열왕기상 19장', E'갈멜 산에서의 놀라운 승리가 있은 직후, 이세벨의 살해 위협을 들은 엘리야는 두려움에 사로잡혀 도망칩니다. 850명의 거짓 선지자들과 맞서 하늘에서 불을 내린 바로 그 선지자가 한 여인의 협박 앞에서 무너진 것입니다. 엘리야는 유다 브엘세바까지 도망친 후, 홀로 광야로 들어가 로뎀 나무 아래에서 차라리 죽기를 간구합니다. "나는 내 조상들보다 낫지 못하니이다"라는 그의 탄식에는 극도의 피로감과 절망이 묻어납니다.\n\n그러나 하나님은 지쳐 쓰러진 엘리야를 꾸짖지 않으셨습니다. 오히려 천사를 보내 그를 어루만지며 "일어나서 먹으라"고 하시고, 숯불에 구운 떡과 물을 예비해 주셨습니다. 두 번에 걸친 하나님의 세심한 돌봄은 엘리야에게 호렙 산까지 40일을 갈 수 있는 힘을 주었습니다. 호렙 산 굴에서 엘리야는 자신만 홀로 남았다고 하소연하지만, 하나님은 강한 바람도, 지진도, 불도 아닌 세미한 음성으로 찾아오십니다. 요란한 기적이 아니라 고요한 임재로 다가오신 것입니다.\n\n하나님은 엘리야에게 새로운 사명을 주십니다. 하사엘과 예후와 엘리사에게 기름을 부어 각각의 역할을 맡기라는 것입니다. 그리고 놀라운 사실을 알려주십니다. "내가 이스라엘 가운데에 칠천 명을 남기리니 다 바알에게 무릎을 꿇지 아니하고 다 바알에게 입맞추지 아니한 자니라." 엘리야가 혼자라고 생각했을 때, 하나님께서는 이미 7천 명의 신실한 백성을 보존하고 계셨던 것입니다.\n\n엘리야는 즉시 순종하여 엘리사를 찾아갑니다. 열두 겨릿소로 밭을 갈던 부유한 농부 엘리사는 엘리야의 부름을 받자 주저 없이 소를 잡아 백성들과 나누어 먹고, 과거와 완전히 결별한 후 엘리야를 따릅니다. 지친 선지자에게 하나님은 쉼과 새 힘을 주셨을 뿐 아니라, 함께 짐을 나누어질 동역자까지 예비해 주신 것입니다. 승리의 순간에도, 절망의 순간에도 변함없이 우리를 돌보시는 하나님의 신실하심이 이 본문 전체를 관통하고 있습니다.', E'오늘의 핵심\n갈멜 산의 승리 후 두려움에 무너진 엘리야를 하나님은 떡과 물로 회복시키시고, 세미한 음성으로 찾아오셔서 새로운 사명과 동역자를 주셨습니다.\n\n묵상 질문\n1. 영적 승리 후에 찾아온 두려움과 무력감을 경험한 적이 있다면, 그때 하나님은 어떤 방법으로 나를 회복시키셨나요?\n2. 하나님께서 강한 바람이나 지진, 불이 아닌 세미한 음성으로 엘리야를 만나신 것이 우리에게 주는 교훈은 무엇일까요?\n3. 혼자라고 생각될 때, 하나님께서 이미 예비하신 동역자나 신앙의 공동체를 발견한 경험이 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-12', E'엘리야에서 엘리사로 (열왕기하 1장)', E'열왕기하 1장', E'아합의 아들 아하시야가 왕이 되었지만, 성경이 기록하는 그의 행적은 놀랍도록 단순합니다. 다락 난간에서 떨어져 병이 들자 이스라엘의 하나님이 아닌 에그론의 신 바알세붑에게 물으러 사자를 보낸 것, 그것이 전부입니다. 왕이 병들었을 때 가장 먼저 찾아야 할 분은 언약의 하나님이셨지만, 아하시야는 이방 신에게로 향했습니다. 이는 단순한 종교적 혼합주의를 넘어, 하나님의 존재 자체를 부정하는 배교 행위였습니다.\n\n"이스라엘에 하나님이 없어서 너희가 에그론의 신 바알세붑에게 물으러 가느냐"(왕하 1:3)는 엘리야의 질책은 아하시야 개인만이 아니라, 하나님을 잊어버린 시대 전체를 향한 탄식이었습니다. 북이스라엘의 왕이 공개적으로 이방 신을 찾는 모습은 온 나라가 얼마나 깊은 영적 타락에 빠져 있는지를 보여줍니다.\n\n하나님께서는 엘리야를 통해 즉각적인 심판의 메시지를 전하셨습니다. 아하시야는 그 침상에서 일어나지 못하고 죽을 것이라는 선언이었습니다. 그러나 왕은 이 경고를 듣고도 회개하지 않았습니다. 오히려 군대를 보내 엘리야를 잡아오려 했습니다. 두 차례에 걸쳐 오십부장과 군사들이 하늘에서 내린 불에 타 죽는 무서운 심판이 있었지만, 왕의 마음은 여전히 완고했습니다.\n\n세 번째 오십부장의 겸손한 간구 앞에서야 엘리야는 왕에게 직접 하나님의 말씀을 전했습니다. 그러나 이미 때는 늦었습니다. 아하시야는 선언된 대로 죽음을 맞이했고, 그의 짧은 통치는 영적 실패의 기록으로만 남았습니다.\n\n이 사건은 우리에게 중요한 교훈을 줍니다. 위기의 순간에 우리가 먼저 찾는 것이 무엇인지가 우리의 진짜 믿음을 드러낸다는 사실입니다. 병들었을 때, 어려움을 만났을 때, 우리는 어디로 먼저 향하고 있습니까? 현대의 바알세붑은 물질만능주의일 수도, 인간의 지혜일 수도, 세상의 권세일 수도 있습니다. 하나님께서는 지금도 우리에게 묻고 계십니다. "너희에게 하나님이 없느냐?"', E'오늘의 핵심\n아하시야가 병들었을 때 하나님이 아닌 이방 신을 찾은 것은 북이스라엘의 깊은 영적 타락을 보여주며, 하나님께서는 이에 대해 즉각적인 심판으로 응답하셨습니다.\n\n묵상 질문\n1. 내가 위기를 만날 때 가장 먼저 의지하는 것은 무엇인가요?\n2. 하나님보다 앞서 찾게 되는 현대의 ''바알세붑''은 무엇일까요?\n3. 영적 경고를 받았을 때 어떻게 반응하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-13', E'엘리야에서 엘리사로 (열왕기하 2장)', E'열왕기하 2장', E'여호와께서 엘리야를 하늘로 올리시려는 날이 이르렀습니다. 길갈에서 벧엘로, 벧엘에서 여리고로, 여리고에서 요단까지 이어지는 여정은 단순한 이동이 아니라 사명이 계승되는 거룩한 과정이었습니다. 엘리야는 세 번이나 "여기 머물라"고 엘리사를 만류했지만, 엘리사는 "여호와께서 살아 계심과 당신의 영혼이 살아 있음을 두고 맹세하노니 내가 당신을 떠나지 아니하겠나이다"라고 답하며 끝까지 스승의 곁을 지켰습니다. 이는 단순한 제자의 충성심을 넘어서는 것이었습니다. 하나님의 역사를 이어받겠다는 간절한 갈망이 그를 붙들고 있었던 것입니다.\n\n요단강 앞에서 엘리야가 겉옷으로 물을 치자 물이 갈라졌습니다. 모세가 홍해를 가른 것처럼, 여호수아가 요단을 건넌 것처럼, 하나님의 능력이 여전히 그의 종과 함께하심을 보여주는 표징이었습니다. 건너편에서 엘리사가 구한 것은 "당신의 성령이 하시는 역사가 갑절이나 내게 있게 하소서"(왕하 2:9)라는 것이었습니다. 재물도 명예도 아닌, 오직 하나님의 일을 감당할 영적 능력을 구했습니다.\n\n불수레와 불말들이 나타나 엘리야가 회오리바람으로 하늘로 올라갔을 때, 엘리사는 "내 아버지여 내 아버지여 이스라엘의 병거와 그 마병이여"라고 외쳤습니다. 한 시대를 지켜온 신앙의 거인이 떠나는 순간이었습니다. 그러나 떨어진 겉옷을 주워 든 엘리사가 요단강 물을 치며 "엘리야의 하나님 여호와는 어디 계시니이까"라고 외쳤을 때, 물이 다시 갈라졌습니다. 하나님의 역사는 사람에게 매이지 않습니다. 엘리야는 떠났지만, 하나님께서는 엘리사를 통해 계속 일하십니다.\n\n새로운 사역의 시작은 여리고의 나쁜 물을 고치는 것이었습니다. 새 그릇에 담긴 소금으로 물의 근원을 치유하시는 하나님의 능력은 죽음과 불모의 땅에 생명을 가져왔습니다. 벧엘에서 일어난 아이들의 조롱과 그에 따른 심판은 하나님의 종을 대하는 태도가 곧 하나님을 대하는 태도임을 엄중히 가르쳐 줍니다.\n\n오늘도 하나님께서는 당신의 일을 이어갈 사람들을 찾고 계십니다. 엘리사처럼 끝까지 따르는 결단과 영적 능력을 사모하는 마음이 있을 때, 우리도 이 시대에 하나님의 도구로 쓰임받을 수 있습니다.', E'오늘의 핵심\n엘리야의 승천과 함께 그의 사역이 엘리사에게 계승되며, 하나님의 구원 역사는 사람이 바뀌어도 멈추지 않고 계속됨을 보여줍니다.\n\n묵상 질문\n1. 엘리사가 끝까지 엘리야를 따른 것처럼, 나는 하나님의 부르심에 끝까지 순종하고 있나요?\n2. "갑절의 영"을 구한 엘리사처럼, 나는 무엇보다 영적인 능력을 사모하고 있나요?\n3. 하나님께서 내 삶을 통해 이루기 원하시는 사역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-10-14', E'일곱 나팔의 심판과 순교자들 (요한계시록 8장)', E'요한계시록 8장', E'일곱째 인이 떼어지자 하늘이 반 시간쯤 고요해집니다. 이 침묵은 단순한 정적이 아니라 거대한 심판이 시작되기 직전의 숨죽인 기다림입니다. 그런데 이 긴장감 넘치는 순간에 우리가 주목해야 할 장면이 펼쳐집니다. 한 천사가 금 향로를 가지고 와서 많은 향을 받아 모든 성도의 기도와 함께 하나님의 보좌 앞 금 제단에 드립니다. 향연이 성도의 기도와 함께 하나님 앞으로 올라가는 모습은 우리에게 중요한 진리를 가르쳐줍니다. 세상이 심판의 문턱에 서 있는 그 순간에도, 성도들의 기도는 멈추지 않고 하나님께 상달되고 있다는 것입니다.\n\n이어서 일곱 천사가 나팔을 불기 시작합니다. 첫째 나팔과 함께 피 섞인 우박과 불이 쏟아져 땅의 삼분의 일이 타버립니다. 둘째 나팔에는 불타는 큰 산과 같은 것이 바다에 던져져 바다의 삼분의 일이 피가 됩니다. 셋째 나팔에는 쓴 쑥이라 불리는 별이 떨어져 물의 삼분의 일을 쓰게 만들어 많은 사람이 죽습니다. 넷째 나팔에는 해와 달과 별들의 삼분의 일이 어두워집니다. \n\n이 재앙들은 출애굽 당시의 열 가지 재앙을 연상시킵니다. 하나님께서는 당신의 백성을 구원하시고 악을 심판하시는 동일한 방법을 사용하고 계십니다. 그러나 여기서 주목할 점은 모든 재앙이 ''삼분의 일''에 제한되어 있다는 것입니다. 이는 하나님의 심판 가운데서도 여전히 회개의 기회를 주시는 은혜를 보여줍니다. 완전한 멸망이 아닌 경고의 성격을 띠고 있는 것입니다.\n\n마지막에 독수리가 공중을 날며 외치는 "화, 화, 화"라는 세 번의 경고는 앞으로 올 더 큰 심판을 예고합니다. 그러나 이 모든 심판의 과정 속에서도 성도의 기도가 하나님 앞에 올려지고 있다는 사실은 우리에게 큰 위로가 됩니다. 혼란과 두려움의 시대를 살아가는 우리도 기도를 통해 하나님과 연결되어 있으며, 그분은 우리의 모든 간구를 들으시고 당신의 때에 응답하신다는 확신을 가질 수 있습니다.', E'오늘의 핵심\n하나님의 심판이 시작되는 엄중한 순간에도 성도들의 기도는 하나님께 상달되며, 심판 가운데서도 회개의 기회를 주시는 하나님의 은혜가 나타납니다.\n\n묵상 질문\n1. 세상의 혼란 속에서도 나의 기도가 하나님께 닿는다는 확신을 가지고 있나요?\n2. 하나님이 ''삼분의 일''로 제한하신 심판을 통해 보여주시는 은혜는 무엇일까요?\n3. 오늘 내가 하나님께 올려드려야 할 간절한 기도는 무엇인가요?');
